title: $:/core/modules/commands/inspect/mcp-lib.js
type: application/javascript
module-type: library

Zero-dependency MCP (Model Context Protocol) server for TiddlyWiki.
Implements JSON-RPC 2.0 over stdio transport.

\*/

"use strict";

var fs = require("fs"),
	path = require("path"),
	net = require("net"),
	crypto = require("crypto");

var tools = require("$:/core/modules/commands/inspect/mcp-tools.js");
var handlers = require("$:/core/modules/commands/inspect/mcp-handlers.js");

var PROTOCOL_VERSION = "2025-03-26";
var SERVER_NAME = "tiddlywiki-mcp";
var PLUGIN_TITLE = "$:/plugins/wikilabs/tw-mcp";

function getServerVersion() {
	var pluginTiddler = $tw.wiki.getTiddler(PLUGIN_TITLE);
	return (pluginTiddler && pluginTiddler.fields.version) || "0.0.0";
}

var readonlyMode = false;
var allowedPaths = null; // null = no restriction, array of absolute paths = restrict output to these directories
var authToken = null; // generated at startup for pipe transport authentication
var serverLabel = null; // optional user-defined label to identify this instance
var pipeClients = {}; // clientId -> { send, socket } — authenticated pipe clients
var currentPipeServer = null; // reference to the active net.Server for the pipe
var takeoverInProgress = false; // guard against concurrent takeover requests

// --- Path validation helpers ---

function isPathAllowed(targetPath) {
	if(!allowedPaths || allowedPaths.length === 0) {
		return true;
	}
	// Normalize separators for consistent comparison (Windows can mix / and \)
	var resolved = path.resolve(targetPath).replace(/\\/g, "/");
	for(var i = 0; i < allowedPaths.length; i++) {
		var allowed = path.resolve(allowedPaths[i]).replace(/\\/g, "/");
		// Ensure allowed ends without trailing slash for consistent prefix matching
		if(allowed.length > 1 && allowed.charAt(allowed.length - 1) === "/") {
			allowed = allowed.slice(0, -1);
		}
		// Check that target is inside or equal to an allowed directory
		if(resolved === allowed || resolved.indexOf(allowed + "/") === 0) {
			return true;
		}
	}
	return false;
}

function checkPathAllowed(targetPath) {
	if(!isPathAllowed(targetPath)) {
		process.stderr.write("[tw-mcp] BLOCKED path: " + path.resolve(targetPath) + " | allowed: " + allowedPaths.join(", ") + "\n");
		return {
			isError: true,
			content: [{ type: "text", text: "Path not allowed: " + path.resolve(targetPath) + ". Allowed directories: " + allowedPaths.join(", ") }]
		};
	}
	return null;
}

// --- JSON-RPC helpers ---

function jsonrpcResponse(id, result) {
	return JSON.stringify({ jsonrpc: "2.0", id: id, result: result });
}

function jsonrpcError(id, code, message, data) {
	var err = { jsonrpc: "2.0", id: id, error: { code: code, message: message } };
	if(data !== undefined) {
		err.error.data = data;
	}
	return JSON.stringify(err);
}

// --- MCP Server ---

// --- Shared message dispatcher (used by stdio and pipe transports) ---

function log(msg) {
	var now = new Date();
	var ts = now.toISOString().slice(11, 23);
	process.stderr.write("[tw-mcp " + ts + "] " + msg + "\n");
}

// Shorten pipe paths after the first mention so repeated log lines stay readable.
var pipePathFullyShown = false;
function fmtPipe(p) {
	if(!p) return p;
	if(!pipePathFullyShown) {
		pipePathFullyShown = true;
		return p;
	}
	var idx = p.lastIndexOf("tiddlywiki-mcp-");
	if(idx < 0) return p;
	var tail = p.slice(idx + "tiddlywiki-mcp-".length);
	if(tail.length > 24) {
		tail = "…" + tail.slice(-22);
	}
	return "pipe:" + tail;
}

// Suppress the redundant "Initialized" log for pipe clients — the auth log already covers it.
var suppressNextInitLog = false;

// Readonly is the default but surprising — most expect RW from a debug tool.
// Render READONLY prominently so users notice when writes are disabled.
function fmtMode() {
	return "mode: " + (readonlyMode ? "READONLY" : "readwrite");
}

// Rolling history of recent requests so we can identify what was cancelled.
// Map: requestId -> { method, toolName, at }
var requestHistory = Object.create(null);
var requestHistoryOrder = [];
var REQUEST_HISTORY_SIZE = 50;

function recordRequest(id, method, toolName) {
	if(id === undefined || id === null) return;
	requestHistory[id] = { method: method, toolName: toolName, at: Date.now() };
	requestHistoryOrder.push(id);
	while(requestHistoryOrder.length > REQUEST_HISTORY_SIZE) {
		var old = requestHistoryOrder.shift();
		delete requestHistory[old];
	}
}

function describeRequest(id) {
	var entry = requestHistory[id];
	if(!entry) return "unknown (id=" + id + ")";
	var elapsed = Date.now() - entry.at;
	var name = entry.toolName ? entry.method + " " + entry.toolName : entry.method;
	return name + " (id=" + id + ", " + elapsed + "ms ago)";
}

function dispatchMessage(line, send) {
	var parsed;
	try {
		parsed = JSON.parse(line);
	} catch(e) {
		send(jsonrpcError(null, -32700, "Parse error"));
		return;
	}

	// Notifications have no id — no response needed
	if(parsed.id === undefined || parsed.id === null) {
		if(parsed.method === "notifications/initialized") {
			log("Client initialized");
		} else if(parsed.method === "notifications/cancelled") {
			var params = parsed.params || {};
			var reason = params.reason || "no reason given";
			log("Request cancelled: " + describeRequest(params.requestId) + " — reason: " + reason);
		} else if(parsed.method === "notifications/takeover-request") {
			handleTakeoverRequest(parsed.params);
		}
		return;
	}

	var id = parsed.id;
	var method = parsed.method;
	var toolName = (method === "tools/call" && parsed.params) ? parsed.params.name : null;
	recordRequest(id, method, toolName);

	switch(method) {
		case "initialize":
			send(jsonrpcResponse(id, {
				protocolVersion: PROTOCOL_VERSION,
				capabilities: {
					tools: {}
				},
				serverInfo: {
					name: SERVER_NAME,
					version: getServerVersion()
				},
				instructions: "TiddlyWiki MCP server." +
					(readonlyMode ? " READONLY mode — writes disabled." : "") +
					($tw.wiki.getTiddler("$:/temp/mcp/html-import") && $tw.wiki.getTiddler("$:/temp/mcp/html-import").fields.status === "pending" ?
						"\n\n## HTML import pending\n" +
						"$:/temp/mcp/html-import staged but not on disk. Read it for analysis, let user review/edit $:/config/FileSystemPaths, then call extract_html_wiki."
						: "") +
					"\n\n## Safety\n" +
					"- Never write tiddlers without explicit user request (create/edit/update/delete/rename/tag/untag). 'list','show','find','search' = read-only.\n" +
					"- Bulk ops: list affected tiddlers and confirm first.\n" +
					"- get_tiddler before overwriting.\n" +
					"\n## System tiddlers\n" +
					"- Default-exclude '$:/' — prepend '!is[system]' to filters unless user asks for system/shadow tiddlers.\n" +
					"- Shadow fallback: if 2-3 searches return empty, retry with '[all[shadows+tiddlers]]'. Many important tiddlers are shadows.\n" +
					"- Don't fetch '$:/core/modules/...' unless user names one.\n" +
					"\n## Token use\n" +
					"- Tool results are pre-formatted; pass through, don't reformat.\n" +
					"- Render/filter/wiki-info → MCP. Code search → Read/Grep/Glob.\n" +
					"\n## Tool choice (trigger words)\n" +
					"- WRITE (create/edit/update/change/fix/delete/rename/tag/untag): get_tiddler(detailed=true) → edit_tiddler for small edits (LINE#HASH anchors), put_tiddler for new tiddlers or full rewrites.\n" +
					"- READ (show/list/find/search/what/how many/which): get_tiddler(detailed=true); format='tid' only when plain text needed.\n" +
					"- RENDER (render/preview/'what does X look like'): render_tiddler (whole), render_field (one field), render_text (raw wikitext). get_tiddler returns SOURCE, not rendered output.\n" +
					"- put_tiddler resends full text — never use for small edits.\n" +
					"- Omit type when it's text/vnd.tiddlywiki (default).\n" +
					"\n## Filters\n" +
					"- Narrow first: '[!is[system]search[x]]'. Shadows: '[all[shadows+tiddlers]prefix[$:/config/]]'.\n" +
					"\n## Single-file HTML wiki import\n" +
					"- import_html_wiki(path) into an empty wiki folder, then extract_html_wiki() once user approves FileSystemPaths.\n" +
					"\n## Hot reload (no server restart)\n" +
					"- Edition tiddlers on disk → reload_tiddlers (scope='tiddlers').\n" +
					"- Non-JS plugin subtiddler in tw-mcp → reload_mcp_modules. Other plugins: user re-adds plugin tiddler so TW auto-reloads.\n" +
					"- tw-mcp JS handler → reload_mcp_modules (disk re-read + JS re-exec).\n" +
					"- mcp.js / mcp-lib.js / shared.js / filesystem.js → full server restart."
			}));
			if(suppressNextInitLog) {
				suppressNextInitLog = false;
			} else {
				log("Initialized (protocol " + PROTOCOL_VERSION + ", " + fmtMode() + ")");
			}
			break;

		case "ping":
			send(jsonrpcResponse(id, {}));
			break;

		case "tools/list":
			send(jsonrpcResponse(id, {
				tools: tools.getToolDefinitions(readonlyMode)
			}));
			break;

		case "tools/call": {
			var toolName = parsed.params && parsed.params.name;
			var toolArgs = (parsed.params && parsed.params.arguments) || {};
			var result = handlers.handleToolCall(toolName, toolArgs);
			if(result === null) {
				send(jsonrpcError(id, -32602, "Unknown tool: " + toolName));
			} else {
				send(jsonrpcResponse(id, result));
			}
			break;
		}

		default:
			send(jsonrpcError(id, -32601, "Method not found: " + method));
			break;
	}
}

// --- Stream handler for newline-delimited JSON-RPC ---

var MAX_BUFFER_SIZE = 100 * 1024 * 1024; // 100MB — generous limit for base64 uploads

function attachStreamHandler(input, send, onClose, customDispatch) {
	var dispatch = customDispatch || function(line, sendFn) { dispatchMessage(line, sendFn); };
	var buffer = "";
	input.setEncoding("utf8");
	input.on("data", function(chunk) {
		buffer += chunk;
		if(buffer.length > MAX_BUFFER_SIZE) {
			log("Buffer overflow — message exceeds " + (MAX_BUFFER_SIZE / 1024 / 1024) + "MB, dropping connection");
			buffer = "";
			input.destroy();
			return;
		}
		var lines = buffer.split("\n");
		buffer = lines.pop();
		for(var i = 0; i < lines.length; i++) {
			var line = lines[i].trim();
			if(line) {
				dispatch(line, send);
			}
		}
	});
	input.on("end", function() {
		if(onClose) {
			onClose();
		}
	});
}

// --- Named pipe transport ---

// Resolve the canonical wiki path by following includeWikis to the root.
// e.g. tw5.com-server includes ../tw5.com → canonical path is tw5.com.
// The pipe name and discovery file are based on this so all editions converge.
function getCanonicalWikiPath() {
	var wikiPath = $tw.boot.wikiPath;
	if(!wikiPath) {
		return null;
	}
	try {
		var infoPath = path.resolve(wikiPath, "tiddlywiki.info");
		var info = JSON.parse(fs.readFileSync(infoPath, "utf8"));
		if(info.includeWikis && info.includeWikis.length > 0) {
			var first = info.includeWikis[0];
			var includePath = typeof first === "string" ? first : first.path;
			return path.resolve(wikiPath, includePath);
		}
	} catch(e) {
		// tiddlywiki.info doesn't exist or is unreadable
	}
	return wikiPath;
}

function getPipePath() {
	var canonical = getCanonicalWikiPath() || "default";
	if(process.platform === "win32") {
		// Windows named pipe — use wiki path hash for uniqueness
		var wikiId = canonical.replace(/[^a-zA-Z0-9]/g, "-");
		return "\\\\.\\pipe\\tiddlywiki-mcp-" + wikiId;
	} else {
		// Unix domain socket in the canonical wiki directory
		return path.resolve(canonical, ".mcp.sock");
	}
}

function isProcessRunning(pid) {
	try {
		process.kill(pid, 0);
		return true;
	} catch(e) {
		return false;
	}
}

function cleanStaleDiscoveryFile() {
	var canonical = getCanonicalWikiPath();
	if(!canonical) {
		return;
	}
	var discoveryFile = path.resolve(canonical, ".tw-mcp", "connect");
	try {
		var raw = fs.readFileSync(discoveryFile, "utf8");
		var data = JSON.parse(raw);
		if(data.pid && !isProcessRunning(data.pid)) {
			log("Removing stale .tw-mcp/connect (PID " + data.pid + " is no longer running)");
			fs.unlinkSync(discoveryFile);
		}
	} catch(e) {
		// Ignore — file doesn't exist or is unreadable
	}
}

function tryReadDiscovery(wikiPath) {
	var discoveryFile = path.resolve(wikiPath, ".tw-mcp", "connect");
	try {
		var raw = fs.readFileSync(discoveryFile, "utf8");
		var data = JSON.parse(raw);
		if(data.pid && data.pipe && data.token && isProcessRunning(data.pid)) {
			return data;
		}
	} catch(e) {
		// File doesn't exist or is unreadable
	}
	return null;
}

function readDiscoveryFile() {
	if(!$tw.boot.wikiPath) {
		return null;
	}
	// includeWikis path takes precedence (shared editions converge here)
	var canonical = getCanonicalWikiPath();
	if(canonical !== $tw.boot.wikiPath) {
		var result = tryReadDiscovery(canonical);
		if(result) {
			return result;
		}
	}
	// Fall back to own wiki directory
	return tryReadDiscovery($tw.boot.wikiPath);
}

function probeAndCleanPipe(pipePath, callback) {
	// Clean up stale discovery files left by hard-killed processes
	cleanStaleDiscoveryFile();
	// Try connecting to the pipe to see if another server is alive.
	// callback(err) — err is null if the pipe is available, or an Error if another server owns it.
	var probe = net.createConnection(pipePath, function() {
		// Connection succeeded — another server is alive
		probe.destroy();
		callback(new Error("Another MCP server is already listening on " + pipePath));
	});
	probe.on("error", function(err) {
		// Connection failed — pipe is stale or doesn't exist
		if(process.platform !== "win32") {
			// On Unix, remove the stale socket file
			try {
				fs.unlinkSync(pipePath);
			} catch(e) {
				// Ignore — file doesn't exist
			}
		}
		callback(null);
	});
	// Short timeout so startup isn't delayed
	probe.setTimeout(1000, function() {
		probe.destroy();
		callback(null);
	});
}

function broadcastToClients(message) {
	var ids = Object.keys(pipeClients);
	for(var i = 0; i < ids.length; i++) {
		var client = pipeClients[ids[i]];
		client.send(message);
	}
}

function startPipeServer() {
	var pipePath = getPipePath();

	var pipeServer = net.createServer(function(socket) {
		var clientId = "pipe-" + Date.now();
		var clientSuffix = ""; // will be set to " @<label>[role]" after auth

		var send = function(msg) {
			if(!socket.destroyed) {
				socket.write(msg + "\n");
			}
		};

		// Pipe clients must authenticate via token in the initialize request.
		// The dispatch wrapper intercepts messages until auth succeeds.
		var authenticated = false;
		var authenticatedDispatch = function(line, sendFn) {
			if(authenticated) {
				return dispatchMessage(line, sendFn);
			}
			// Not yet authenticated — parse and check
			var parsed;
			try {
				parsed = JSON.parse(line);
			} catch(e) {
				sendFn(jsonrpcError(null, -32700, "Parse error"));
				return;
			}
			// First message must be initialize with a valid _auth_token
			if(parsed.method !== "initialize" || parsed.id === undefined || parsed.id === null) {
				sendFn(jsonrpcError(parsed.id || null, -32600, "Authentication required: first message must be initialize with _auth_token"));
				socket.destroy();
				return;
			}
			var clientToken = parsed.params && parsed.params._auth_token;
			if(!clientToken || typeof clientToken !== "string") {
				sendFn(jsonrpcError(parsed.id, -32600, "Authentication failed: missing _auth_token"));
				socket.destroy();
				return;
			}
			// Constant-time comparison to prevent timing attacks
			var tokenBuf = Buffer.from(authToken, "utf8");
			var clientBuf = Buffer.from(clientToken, "utf8");
			if(tokenBuf.length !== clientBuf.length || !crypto.timingSafeEqual(tokenBuf, clientBuf)) {
				sendFn(jsonrpcError(parsed.id, -32600, "Authentication failed: invalid token"));
				log("Auth failed for client " + clientId + " — invalid token" + clientSuffix);
				socket.destroy();
				return;
			}
			authenticated = true;
			// Append PID to clientId, keep label/role separate so they're always last
			var clientPid = parsed.params && parsed.params._pid;
			var clientLabel = parsed.params && parsed.params._label;
			var clientRole = parsed.params && parsed.params._role;
			if(clientPid) {
				clientId = clientId + " (PID " + clientPid + ")";
			}
			if(clientLabel) {
				clientSuffix = " @" + clientLabel;
			}
			if(clientRole) {
				clientSuffix = clientSuffix + " [" + clientRole + "]";
			}
			log("Client ready: " + clientId + clientSuffix + " (protocol " + PROTOCOL_VERSION + ", " + fmtMode() + ")");
			// Register in client registry for broadcast
			pipeClients[clientId] = { send: sendFn, socket: socket };
			// Suppress the redundant per-client "Initialized" log — the line above already covers it
			suppressNextInitLog = true;
			// Forward the initialize message to the normal dispatcher
			dispatchMessage(line, sendFn);
		};

		attachStreamHandler(socket, send, function() {
			delete pipeClients[clientId];
			log("Client gone: " + clientId + clientSuffix);
		}, authenticatedDispatch);

		socket.on("error", function(err) {
			delete pipeClients[clientId];
			log("Client error: " + clientId + clientSuffix + " — " + err.message);
		});
	});

	pipeServer.on("error", function(err) {
		if(err.code === "EADDRINUSE") {
			log("Pipe already in use: " + fmtPipe(pipePath) + " — another MCP server may be running for this wiki");
		} else {
			log("Pipe server error: " + err.message);
		}
	});

	// Cleanup: close pipe server and remove discovery file if we created it (PID check)
	var canonical = getCanonicalWikiPath();
	function cleanup() {
		pipeServer.close();
		if(canonical) {
			var cleanupFile = path.resolve(canonical, ".tw-mcp", "connect");
			try {
				var raw = fs.readFileSync(cleanupFile, "utf8");
				var data = JSON.parse(raw);
				if(data.pid === process.pid) {
					fs.unlinkSync(cleanupFile);
				}
			} catch(e) {
				// Ignore — file doesn't exist or is unreadable
			}
		}
		if(process.platform !== "win32") {
			try {
				fs.unlinkSync(pipePath);
			} catch(e) {
				// Ignore
			}
		}
	}
	process.on("exit", cleanup);
	process.on("SIGINT", function() { cleanup(); process.exit(0); });
	process.on("SIGTERM", function() { cleanup(); process.exit(0); });

	// Probe the pipe before listening — detect if another server already owns it
	probeAndCleanPipe(pipePath, function(probeErr) {
		if(probeErr) {
			log(probeErr.message);
			log("Pipe transport disabled — stdio transport is still active");
			return;
		}
		pipeServer.listen(pipePath, function() {
			log("Pipe server listening: " + fmtPipe(pipePath));
			// Restrict socket permissions on Unix to owner only
			if(process.platform !== "win32") {
				try {
					fs.chmodSync(pipePath, 0o600);
				} catch(e) {
					log("Warning: could not restrict socket permissions: " + e.message);
				}
			}
			// Write discovery file to the canonical wiki path so all editions converge
			writeDiscoveryFile({ pipe: pipePath, token: authToken, pid: process.pid, label: serverLabel || undefined, listen: !!$tw.httpServer });
		});
	});

	return pipeServer;
}

// --- Takeover: primary steps down, new primary takes over ---

function writeDiscoveryFile(data) {
	var canonical = getCanonicalWikiPath();
	if(!canonical) {
		return;
	}
	var mcpDir = path.resolve(canonical, ".tw-mcp");
	var discoveryFile = path.resolve(mcpDir, "connect");
	try {
		$tw.utils.createDirectory(mcpDir);
		fs.writeFileSync(discoveryFile, JSON.stringify(data), { encoding: "utf8", mode: 0o600 });
	} catch(e) {
		log("Warning: could not write .tw-mcp/connect discovery file: " + e.message);
	}
}

function handleTakeoverRequest(params) {
	if(takeoverInProgress) {
		log("Takeover already in progress, ignoring request from PID " + params.pid);
		return;
	}
	if(!params || !params.pid) {
		log("Invalid takeover-request: missing params");
		return;
	}
	takeoverInProgress = true;
	log("Takeover requested by PID " + params.pid + (params.label ? " @" + params.label : ""));

	// Broadcast takeover notification to all pipe clients so they know to reconnect
	var notification = JSON.stringify({
		jsonrpc: "2.0",
		method: "notifications/takeover",
		params: { pid: params.pid, label: params.label }
	});
	broadcastToClients(notification);

	// Remove discovery file so the new primary can write its own
	var canonical = getCanonicalWikiPath();
	if(canonical) {
		try {
			fs.unlinkSync(path.resolve(canonical, ".tw-mcp", "connect"));
		} catch(e) {
			// Ignore
		}
	}

	// Close our pipe server after a short delay to flush broadcasts.
	// The new primary will start its pipe server on the now-free path.
	// Then we'll read its discovery file and connect as proxy.
	setTimeout(function() {
		// Destroy all client sockets so proxies detect the disconnect
		var ids = Object.keys(pipeClients);
		for(var i = 0; i < ids.length; i++) {
			var client = pipeClients[ids[i]];
			if(client.socket && !client.socket.destroyed) {
				client.socket.destroy();
			}
		}
		pipeClients = {};
		if(currentPipeServer) {
			currentPipeServer.close();
			currentPipeServer = null;
		}

		// Wait for new primary to write its discovery file, then connect as proxy
		waitForNewPrimary(params.pid);
	}, 100);
}

function waitForNewPrimary(expectedPid) {
	var attempts = 0;
	var maxAttempts = 30; // 3 seconds max
	function check() {
		attempts++;
		var discovery = readDiscoveryFile();
		if(discovery && discovery.pid === expectedPid) {
			log("New primary discovered (PID " + discovery.pid + "), connecting as proxy");
			transitionToProxy(discovery);
			return;
		}
		if(attempts < maxAttempts) {
			setTimeout(check, 100);
		} else {
			log("Timed out waiting for new primary (PID " + expectedPid + "), staying as primary");
			takeoverInProgress = false;
			// Re-start pipe server since we closed ours
			currentPipeServer = startPipeServer();
			$tw.mcp.role = "primary";
		}
	}
	check();
}

// stdinRelay: swappable function ref for stdin dispatch — set by startAsPrimary,
// swapped by transitionToProxy to relay mode
var stdinRelay = null;

function transitionToProxy(newPrimary) {
	log("Stepping down to PROXY → new primary (PID " + newPrimary.pid + ") at " + fmtPipe(newPrimary.pipe) + (newPrimary.label ? " @" + newPrimary.label : ""));
	$tw.mcp.role = "proxy";
	takeoverInProgress = false;

	// Connect to new primary's pipe
	var proxySocket = net.createConnection(newPrimary.pipe, function() {
		log("Transition: connected to new primary");
		// Send initialize with auth token to authenticate.
		// _role: "former-primary" tells the new primary we're the old one reconnecting as proxy.
		var initMsg = JSON.stringify({
			jsonrpc: "2.0",
			id: "transition-init",
			method: "initialize",
			params: {
				protocolVersion: PROTOCOL_VERSION,
				_auth_token: newPrimary.token,
				_pid: process.pid,
				_label: serverLabel,
				_role: "former-primary"
			}
		});
		proxySocket.write(initMsg + "\n");
		// Flush any pending stdin lines
		for(var i = 0; i < pendingRelay.length; i++) {
			proxySocket.write(pendingRelay[i] + "\n");
		}
		pendingRelay = [];
		proxyConnected = true;
	});

	proxySocket.setEncoding("utf8");
	var proxyConnected = false;
	var pendingRelay = [];
	var proxyBuffer = "";

	// Relay: new primary pipe → stdout
	proxySocket.on("data", function(chunk) {
		proxyBuffer += chunk;
		var lines = proxyBuffer.split("\n");
		proxyBuffer = lines.pop();
		for(var i = 0; i < lines.length; i++) {
			var line = lines[i].trim();
			if(line) {
				// Suppress the initialize response we sent for auth
				try {
					var msg = JSON.parse(line);
					if(msg.id === "transition-init") {
						continue;
					}
				} catch(e) {
					// pass through
				}
				process.stdout.write(line + "\n");
			}
		}
	});

	proxySocket.on("error", function(err) {
		log("Transition proxy: pipe error — " + err.message);
	});

	proxySocket.on("end", function() {
		log("Transition proxy: new primary disconnected, exiting");
		process.exit(1);
	});

	// Swap stdin dispatch to relay mode
	stdinRelay = function(line) {
		var modified = injectAuth(line, newPrimary.token, serverLabel);
		if(proxyConnected && proxySocket && !proxySocket.destroyed) {
			proxySocket.write(modified + "\n");
		} else {
			pendingRelay.push(modified);
		}
	};
}

// --- Proxy mode helpers ---

function injectAuth(line, token, label) {
	try {
		var msg = JSON.parse(line);
		if(msg.method === "initialize") {
			msg.params = msg.params || {};
			msg.params._auth_token = token;
			msg.params._pid = process.pid;
			if(label) {
				msg.params._label = label;
			}
			return JSON.stringify(msg);
		}
	} catch(e) {
		// Not valid JSON — pass through
	}
	return line;
}

function startProxyMode(discovery) {
	var pipePath = discovery.pipe;
	var token = discovery.token;
	var pipeSocket = null;
	var connected = false;
	var pendingStdio = [];
	var initializeId = null;
	var toolsListIds = {}; // track tools/list request ids for readonly filtering
	// Build write tool name set for readonly enforcement
	var writeToolNames = {};
	tools.writeTools.forEach(function(t) { writeToolNames[t.name] = true; });

	var takingOver = false; // true when we received a takeover notification (other proxies)
	var initiatedTakeover = false; // true when WE requested the takeover
	var takeoverStartedAt = 0; // ms timestamp for elapsed-time reporting
	var currentPrimaryPid = discovery.pid;

	$tw.mcp.role = "proxy";
	log("Server started as PROXY (PID " + process.pid + ", " + fmtMode() + ") → primary (PID " + discovery.pid + ") at " + fmtPipe(pipePath) + (serverLabel ? " @" + serverLabel : ""));

	// --- Pipe connection to primary ---
	var proxyAuthenticated = false; // true after our self-init is ack'd
	var selfInitId = "proxy-init-" + Date.now();

	pipeSocket = net.createConnection(pipePath, function() {
		connected = true;
		log("Proxy: connected to primary");
		// Send our own initialize to authenticate with the primary's pipe
		var selfInit = injectAuth(JSON.stringify({
			jsonrpc: "2.0",
			id: selfInitId,
			method: "initialize",
			params: { protocolVersion: PROTOCOL_VERSION }
		}), token, serverLabel);
		pipeSocket.write(selfInit + "\n");
		// Flush buffered client messages (client's initialize will be a second init — harmless)
		for(var i = 0; i < pendingStdio.length; i++) {
			pipeSocket.write(pendingStdio[i] + "\n");
		}
		pendingStdio = [];
	});

	pipeSocket.setEncoding("utf8");

	// Relay: pipe -> stdout
	var pipeBuffer = "";
	pipeSocket.on("data", function(chunk) {
		pipeBuffer += chunk;
		var lines = pipeBuffer.split("\n");
		pipeBuffer = lines.pop();
		for(var i = 0; i < lines.length; i++) {
			var line = lines[i].trim();
			if(line) {
				// Intercept takeover notification
				try {
					var notification = JSON.parse(line);
					if(notification.method === "notifications/takeover" && notification.params) {
						if(notification.params.pid === process.pid) {
							// We initiated this takeover — ignore our own notification
							continue;
						}
						takingOver = true;
						log("Proxy: takeover notification — new primary is PID " + notification.params.pid + (notification.params.label ? " @" + notification.params.label : ""));
						// Don't reconnect yet — wait for pipe disconnect + new discovery file
						continue; // don't forward to client
					}
				} catch(e) {
					// Not valid JSON — pass through
				}
				// Suppress our self-init response and trigger takeover if applicable
				if(!proxyAuthenticated) {
					try {
						var selfResp = JSON.parse(line);
						if(selfResp.id === selfInitId) {
							proxyAuthenticated = true;
							log("Proxy: authenticated with primary");
							if($tw.httpServer && !takingOver) {
								setTimeout(initiateTakeover, 0);
							}
							continue; // don't forward self-init response to client
						}
					} catch(e) {}
				}
				// Intercept responses that need proxy-side modification
				if(initializeId !== null || (readonlyMode && Object.keys(toolsListIds).length > 0)) {
					try {
						var resp = JSON.parse(line);
						if(resp.id !== undefined) {
							// Annotate initialize response with proxy info
							if(resp.id === initializeId && resp.result && resp.result.serverInfo) {
								resp.result.serverInfo.proxy = true;
								resp.result.serverInfo.primaryPid = discovery.pid;
								resp.result.serverInfo.primaryLabel = discovery.label || null;
								initializeId = null;
								line = JSON.stringify(resp);
							}
							// Filter write tools from tools/list response when proxy is readonly
							if(readonlyMode && toolsListIds[resp.id] && resp.result && resp.result.tools) {
								resp.result.tools = resp.result.tools.filter(function(t) {
									return !writeToolNames[t.name];
								});
								delete toolsListIds[resp.id];
								line = JSON.stringify(resp);
							}
						}
					} catch(e) {
						// Not valid JSON — pass through
					}
				}
				process.stdout.write(line + "\n");
			}
		}
	});

	pipeSocket.on("error", function(err) {
		log("Proxy: pipe error — " + err.message);
		handlePrimaryDisconnect();
	});

	pipeSocket.on("end", function() {
		log("Proxy: primary disconnected" + (initiatedTakeover ? " (stepping up)" : ""));
		handlePrimaryDisconnect();
	});

	function handlePrimaryDisconnect() {
		connected = false;
		pipeSocket = null;
		if(initiatedTakeover) {
			becomePrimary();
			return;
		}
		if(takingOver) {
			// We received a takeover notification — wait for new discovery file
			waitForNewDiscovery();
			return;
		}
		// Check if a new primary appeared (e.g. takeover we missed)
		var newDiscovery = readDiscoveryFile();
		if(newDiscovery && newDiscovery.pid !== currentPrimaryPid) {
			log("Proxy: primary changed, reconnecting to new primary (PID " + newDiscovery.pid + ")");
			reconnectToNewPrimary(newDiscovery);
			return;
		}
		log("Proxy: primary is gone, exiting");
		process.exit(1);
	}

	function reconnectToNewPrimary(params) {
		// Disconnect from old primary
		if(pipeSocket && !pipeSocket.destroyed) {
			pipeSocket.destroy();
		}
		pipePath = params.pipe;
		token = params.token;
		currentPrimaryPid = params.pid;
		connected = false;
		takingOver = false;

		// Connect to new primary
		pipeSocket = net.createConnection(params.pipe, function() {
			connected = true;
			log("Proxy: reconnected to new primary (PID " + params.pid + ")");
			// Flush any pending messages
			for(var i = 0; i < pendingStdio.length; i++) {
				pipeSocket.write(pendingStdio[i] + "\n");
			}
			pendingStdio = [];
		});

		pipeSocket.setEncoding("utf8");

		// Re-wire pipe data relay (reuse existing pipeBuffer)
		pipeBuffer = "";
		pipeSocket.on("data", function(chunk) {
			pipeBuffer += chunk;
			var lines = pipeBuffer.split("\n");
			pipeBuffer = lines.pop();
			for(var i = 0; i < lines.length; i++) {
				var line = lines[i].trim();
				if(line) {
					// Check for further takeover
					try {
						var notification = JSON.parse(line);
						if(notification.method === "notifications/takeover" && notification.params) {
							takingOver = true;
							log("Proxy: takeover notification — reconnecting to new primary (PID " + notification.params.pid + ")");
							reconnectToNewPrimary(notification.params);
							return;
						}
					} catch(e) {}
					process.stdout.write(line + "\n");
				}
			}
		});

		pipeSocket.on("error", function(err) {
			log("Proxy: pipe error — " + err.message);
			handlePrimaryDisconnect();
		});

		pipeSocket.on("end", function() {
			log("Proxy: primary disconnected");
			handlePrimaryDisconnect();
		});

		// Send initialize with auth to authenticate with new primary
		var initMsg = injectAuth(JSON.stringify({
			jsonrpc: "2.0",
			id: "reconnect-init-" + Date.now(),
			method: "initialize",
			params: { protocolVersion: PROTOCOL_VERSION }
		}), params.token, serverLabel);

		if(connected) {
			pipeSocket.write(initMsg + "\n");
		} else {
			pendingStdio.push(initMsg);
		}
	}

	// --- Takeover initiation (when this proxy also runs --listen) ---

	function waitForNewDiscovery() {
		var attempts = 0;
		var maxAttempts = 30;
		function check() {
			attempts++;
			var newDiscovery = readDiscoveryFile();
			if(newDiscovery && newDiscovery.pid !== currentPrimaryPid) {
				log("Proxy: new primary found (PID " + newDiscovery.pid + "), reconnecting");
				reconnectToNewPrimary(newDiscovery);
				return;
			}
			if(attempts < maxAttempts) {
				setTimeout(check, 100);
			} else {
				log("Proxy: timed out waiting for new primary, exiting");
				process.exit(1);
			}
		}
		check();
	}

	function initiateTakeover() {
		initiatedTakeover = true;
		takeoverStartedAt = Date.now();
		log("── Takeover initiated ──");
		log("   reason: --listen (HTTP server) detected in this process");
		log("   old primary: PID " + currentPrimaryPid);
		log("   new primary: PID " + process.pid + (serverLabel ? " @" + serverLabel : ""));

		// Send takeover request to current primary
		var request = JSON.stringify({
			jsonrpc: "2.0",
			method: "notifications/takeover-request",
			params: {
				pid: process.pid,
				label: serverLabel
			}
		});
		if(connected && pipeSocket && !pipeSocket.destroyed) {
			pipeSocket.write(request + "\n");
		}
	}

	// Called when pipe disconnects during takeover — old primary has stepped down
	function becomePrimary() {
		log("Old primary stepped down, becoming PRIMARY");
		// Generate auth token and init handlers
		authToken = crypto.randomBytes(32).toString("hex");
		if(!allowedPaths && $tw.boot.wikiPath) {
			var canonical = getCanonicalWikiPath() || $tw.boot.wikiPath;
			allowedPaths = [
				$tw.boot.wikiTiddlersPath || path.resolve(canonical, "tiddlers"),
				path.resolve(canonical, "files"),
				path.resolve(canonical, "output"),
				path.resolve($tw.boot.wikiPath, "tiddlers"),
				path.resolve($tw.boot.wikiPath, "files"),
				path.resolve($tw.boot.wikiPath, "output")
			];
		}
		handlers.init({
			readonlyMode: readonlyMode,
			checkPathAllowed: checkPathAllowed
		});

		// Start pipe server on the now-free path
		currentPipeServer = startPipeServer();

		// Swap stdin from relay to dispatch mode
		proxyStdinHandler = function(line) {
			dispatchMessage(line, stdioSend);
		};
		$tw.mcp.role = "primary";
		log("Server started as PRIMARY (PID " + process.pid + ")" + (serverLabel ? " @" + serverLabel : ""));
		var elapsed = Date.now() - takeoverStartedAt;
		log("── Takeover complete (" + elapsed + "ms) ──");
	}

	// --- Relay: stdin -> pipe (swappable via proxyStdinHandler for takeover) ---
	var proxyStdinHandler = relayToPrimary;
	var stdioSend = function(msg) {
		process.stdout.write(msg + "\n");
	};
	var stdioBuffer = "";
	process.stdin.setEncoding("utf8");
	process.stdin.on("data", function(chunk) {
		stdioBuffer += chunk;
		var lines = stdioBuffer.split("\n");
		stdioBuffer = lines.pop();
		for(var i = 0; i < lines.length; i++) {
			var line = lines[i].trim();
			if(line) {
				proxyStdinHandler(line);
			}
		}
	});
	process.stdin.on("end", function() {
		log("stdin closed, shutting down");
		if(pipeSocket && !pipeSocket.destroyed) {
			pipeSocket.destroy();
		}
		process.exit(0);
	});

	function relayToPrimary(line) {
		var modified = injectAuth(line, token, serverLabel);
		// Intercept requests that need proxy-side handling
		try {
			var msg = JSON.parse(line);
			if(msg.id !== undefined) {
				if(msg.method === "initialize") {
					initializeId = msg.id;
				}
				// Track tools/list requests for readonly filtering of responses
				if(readonlyMode && msg.method === "tools/list") {
					toolsListIds[msg.id] = true;
				}
				// Block write tool calls locally when proxy is readonly
				if(readonlyMode && msg.method === "tools/call") {
					var toolName = msg.params && msg.params.name;
					if(toolName && writeToolNames[toolName]) {
						var errResp = jsonrpcResponse(msg.id, {
							isError: true,
							content: [{ type: "text", text: "Tool '" + toolName + "' is disabled in readonly mode" }]
						});
						process.stdout.write(errResp + "\n");
						return; // don't forward to primary
					}
				}
			}
		} catch(e) {
			// Ignore parse errors
		}
		if(connected && pipeSocket && !pipeSocket.destroyed) {
			pipeSocket.write(modified + "\n");
		} else {
			pendingStdio.push(modified);
		}
	}
}

// --- MCP Server entry point ---

function startAsPrimary(options) {
	// Generate auth token for pipe transport (256-bit random hex)
	authToken = crypto.randomBytes(32).toString("hex");
	// Default allowed paths: wiki's tiddlers/, files/, and output/ subdirectories
	if(options.allowedPaths) {
		allowedPaths = options.allowedPaths;
	} else if($tw.boot.wikiPath) {
		var canonical = getCanonicalWikiPath() || $tw.boot.wikiPath;
		var pathSet = {};
		var paths = [
			$tw.boot.wikiTiddlersPath || path.resolve(canonical, "tiddlers"),
			path.resolve(canonical, "files"),
			path.resolve(canonical, "output"),
			path.resolve($tw.boot.wikiPath, "tiddlers"),
			path.resolve($tw.boot.wikiPath, "files"),
			path.resolve($tw.boot.wikiPath, "output")
		];
		allowedPaths = [];
		for(var pi = 0; pi < paths.length; pi++) {
			var resolved = path.resolve(paths[pi]);
			if(!pathSet[resolved]) {
				pathSet[resolved] = true;
				allowedPaths.push(resolved);
			}
		}
	} else {
		allowedPaths = null;
	}

	// Initialize handlers with shared state
	handlers.init({
		readonlyMode: readonlyMode,
		checkPathAllowed: checkPathAllowed
	});

	// stdio transport — uses stdinRelay indirection so transitionToProxy can swap to relay mode
	var stdioSend = function(msg) {
		process.stdout.write(msg + "\n");
	};
	stdinRelay = null; // reset; when null, dispatch normally
	attachStreamHandler(process.stdin, stdioSend, function() {
		log("stdin closed, shutting down");
		process.exit(0);
	}, function(line, sendFn) {
		if(stdinRelay) {
			stdinRelay(line);
		} else {
			dispatchMessage(line, sendFn);
		}
	});

	// Named pipe transport
	currentPipeServer = startPipeServer();

	$tw.mcp.role = "primary";
	log("Server started as PRIMARY (v" + getServerVersion() + ", PID " + process.pid + ", protocol " + PROTOCOL_VERSION + ", " + fmtMode() + ", filesystem: " + !!$tw.syncadaptor + ")" + (serverLabel ? " @" + serverLabel : ""));
	if(allowedPaths) {
		log("Allowed paths:\n  - " + allowedPaths.join("\n  - "));
	}
}

// Detect IDE-spawned process and derive a workspace tag so instances launched
// from different VSCode windows are distinguishable in logs and heartbeats.
function deriveIDEWorkspaceTag() {
	var env = process.env;
	var fromIDE = !!(env.VSCODE_PID || env.VSCODE_IPC_HOOK || env.TERM_PROGRAM === "vscode" || env.CLAUDECODE || env.CLAUDE_CODE_ENTRYPOINT);
	if(!fromIDE) {
		return null;
	}
	var tag = path.basename(process.cwd());
	var wikiPath = $tw && $tw.boot && $tw.boot.wikiPath;
	if(wikiPath) {
		var wikiBase = path.basename(path.resolve(wikiPath));
		if(wikiBase && wikiBase !== tag) {
			tag = tag + "/" + wikiBase;
		}
	}
	return tag || null;
}

function startMCPServer(options) {
	options = options || {};
	readonlyMode = !!options.readonly;
	serverLabel = options.label || null;
	var ideTag = deriveIDEWorkspaceTag();
	if(ideTag) {
		serverLabel = serverLabel ? (serverLabel + ":" + ideTag) : ideTag;
	}

	// Expose MCP state on $tw so other commands (e.g. --listen) can discover it
	$tw.mcp = {
		pid: process.pid,
		label: serverLabel,
		role: null,
		readonly: readonlyMode,
		version: getServerVersion(),
		started: Date.now(),
		heartbeat: function() {
			return {
				pid: process.pid,
				role: $tw.mcp.role,
				label: $tw.mcp.label,
				version: getServerVersion(),
				uptime: Date.now() - $tw.mcp.started,
				readonly: $tw.mcp.readonly
			};
		}
	};

	// Check for an existing primary server via the discovery file
	var discovery = readDiscoveryFile();
	if(discovery) {
		// Verify the primary is actually reachable via pipe
		var probe = net.createConnection(discovery.pipe, function() {
			probe.destroy();
			startProxyMode(discovery);
		});
		probe.on("error", function() {
			log("Discovery file exists but pipe is unreachable — becoming primary");
			cleanStaleDiscoveryFile();
			startAsPrimary(options);
		});
		probe.setTimeout(1000, function() {
			probe.destroy();
			log("Pipe probe timed out — becoming primary");
			cleanStaleDiscoveryFile();
			startAsPrimary(options);
		});
		return;
	}

	startAsPrimary(options);
}

exports.startMCPServer = startMCPServer;
exports.readDiscoveryFile = readDiscoveryFile;
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/mcp-tools.js":{"title":"$:/core/modules/commands/inspect/mcp-tools.js","text":"/*\
title: $:/core/modules/commands/inspect/mcp-tools.js
type: application/javascript
module-type: library

MCP tool definitions (input schemas) for TiddlyWiki MCP server.

\*/

"use strict";

var readTools = [
	{
		name: "get_tiddler",
		description: "Get tiddler fields. Default: metadata only. detailed:true adds text field as hashlines ('LINE#HASH: text' per line; pass anchors to edit_tiddler). format='tid': plain text. Plugin tiddlers return fields + shadow-tiddler tree (format/detailed ignored).",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", description: "The tiddler title" },
				format: { type: "string", enum: ["tid", "json", "hashline"], default: "hashline", description: "hashline (default) — text with hash anchors for editing. tid — plain text. json — structured fields." },
				detailed: { type: "boolean", default: false, description: "Include the text field" }
			},
			required: ["title"]
		}
	},
	{
		name: "get_tiddlers",
		description: "Batch fetch tiddlers by titles array. Text output: `.tid` blocks separated by `\\n+\\n` (CompoundTiddlers); each block `title:` first, other fields alpha, blank, text (if detailed). JSON: `{tiddlers, missing?, truncated?}`. Missing → trailing `Missing: a, b` line (text) or `missing` array (JSON). Truncation trailer: `(N entries truncated; raise max_tiddlers or max_bytes)`. Plugin tiddlers: fields-only. Default skips bookkeeping fields (created/modified/creator/modifier/revision); `verbose=true` includes. Caps: max_tiddlers=50, max_bytes=50000. Default `detailed=true`.",
		inputSchema: {
			type: "object",
			properties: {
				titles: { type: "array", items: { type: "string" }, description: "Array of tiddler titles to fetch (input order preserved)" },
				format: { type: "string", enum: ["tid", "json", "hashline"], default: "hashline", description: "hashline (default) text+hash anchors; tid plain text; json structured (parseable document)" },
				detailed: { type: "boolean", default: true, description: "Include text field. Ignored for plugin tiddlers (always fields-only). Set false for metadata-only batch." },
				verbose: { type: "boolean", default: false, description: "Include bookkeeping fields (created/modified/creator/modifier/revision). Default false drops them as noise." },
				max_tiddlers: { type: "number", default: 50 },
				max_bytes: { type: "number", default: 50000 }
			},
			required: ["titles"]
		}
	},
	{
		name: "run_filter",
		description: "Execute TW filter expression. Returns titles, capped at 500 (output prefixed '(N total, showing first 500)' if truncated). Empty: '(no results)'. Filter max 10000 chars.",
		inputSchema: {
			type: "object",
			properties: {
				filter: { type: "string", description: "TiddlyWiki filter expression" }
			},
			required: ["filter"]
		}
	},
	{
		name: "render_tiddler",
		description: "Render tiddler to text/HTML. mode='raw' (default): type parser. mode='viewtemplate': $:/tags/ViewTemplateBodyFilter cascade — output depends on type/tags, may include framing widgets (e.g. code-mirror frame) for non-wikitext types instead of body content.",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", description: "Tiddler title" },
				type: { type: "string", enum: ["text/plain", "text/plain-formatted", "text/html"], default: "text/plain-formatted" },
				mode: { type: "string", enum: ["raw", "viewtemplate"], default: "raw", description: "raw = type parser (default), viewtemplate = ViewTemplate body cascade" }
			},
			required: ["title"]
		}
	},
	{
		name: "render_field",
		description: "Render tiddler field or data tiddler index as wikitext. Errors on missing/empty (not silent empty).",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", description: "Tiddler title" },
				field: { type: "string", default: "text", description: "Field name (default: text)" },
				index: { type: "string", description: "Data tiddler index (alternative to field)" },
				output: { type: "string", enum: ["text/plain", "text/plain-formatted", "text/html"], default: "text/html", description: "Output type" }
			},
			required: ["title"]
		}
	},
	{
		name: "render_text",
		description: "Render wikitext to plain text, HTML, or parse tree. Full macro/procedure context.",
		inputSchema: {
			type: "object",
			properties: {
				text: { type: "string", description: "Wikitext to render" },
				type: { type: "string", default: "text/vnd.tiddlywiki", description: "Input type" },
				output: { type: "string", enum: ["text/plain", "text/plain-formatted", "text/html", "parsetree"], default: "text/plain", description: "Output type" },
				context: { type: "string", description: "Context tiddler (sets currentTiddler)" },
				exclude: { type: "array", items: { type: "string" }, description: "Keys to omit from parsetree" },
				include: { type: "array", items: { type: "string" }, description: "Keys to unfold in parsetree" }
			},
			required: ["text"]
		}
	},
	{
		name: "inspect_tree",
		description: "Analyze rendered widget tree. Output: type counts, unique link targets, depth-limited JSON (depth=3, structural recursion only). Text nodes ≤10 chars shown verbatim; longer shown as '…N' (length only — leading ellipsis chosen because real text rarely starts with one). include:['text'] inlines text in full, but caps individual nodes at 2000 chars: above that, output is '…N:<first 100>…<last 100>' (head+tail sample with full length N) to prevent runaway. Children capped at 10/parent ('+N more'). exclude drops attributes.",
		inputSchema: {
			type: "object",
			properties: {
				text: { type: "string", description: "Wikitext to analyze" },
				type: { type: "string", default: "text/vnd.tiddlywiki" },
				context: { type: "string", description: "Context tiddler" },
				exclude: { type: "array", items: { type: "string" }, description: "Attributes to omit" },
				include: { type: "array", items: { type: "string" }, description: "Keys to unfold" },
				depth: { type: "number", default: 3, description: "Max tree depth" }
			},
			required: ["text"]
		}
	},
	{
		name: "inspect_pos",
		description: "Render wikitext to HTML with source-position attrs + title index header. Header: [0=Title 1=Title ...]. Each node may carry p=\"idx:line\" or p=\"idx:start-end\" (idx→header, lines in defining tiddler), v=\"name\" (transcluded procedure/macro/variable that produced this node), c=\"A|B|C\" (caller chain — closest enclosing transclude first, outermost last), and ctx=\"Title\" (currentTiddler when it differs from the source-context tiddler — distinguishes repeated list items). Pair with inspect_scope.",
		inputSchema: {
			type: "object",
			properties: {
				text: { type: "string", description: "Wikitext to render" },
				type: { type: "string", default: "text/vnd.tiddlywiki" },
				context: { type: "string", description: "Context tiddler" }
			},
			required: ["text"]
		}
	},
	{
		name: "get_wiki_info",
		description: "Wiki metadata: title, version, tiddler counts, plugins, themes, settings.",
		inputSchema: {
			type: "object",
			properties: {},
			required: []
		}
	},
	{
		name: "search_lines",
		description: "Per-line text search. Output per match: title header, indented '<n>#<hash>: text' for text field (anchor → edit_tiddler `pos`) or 'field:L<n>: text' for other fields. With context>0, context lines prefixed '- ' (also anchored); '--' separates non-adjacent context blocks. Footer: 'N lines matched in M tiddlers'; '(truncated...)' suffix when caps hit. Empty: '(no matches)'. Caps count matches only (context is free). Defaults: fields=['text'], case-insensitive literal, context=0. Asymmetric via context_before / context_after. Filter form: [search-lines:fields:flags[pattern],[before],[after]] (range-style operands); `]`-bearing regex via `{Title}` or `<var>`.",
		inputSchema: {
			type: "object",
			properties: {
				pattern: { type: "string", description: "Search pattern (literal by default; regex when regexp=true)" },
				fields: { type: "array", items: { type: "string" }, description: "Fields to scan; default ['text']. Multiline fields produce per-line matches; single-line fields at most one (lineNumber=1)." },
				regexp: { type: "boolean", default: false },
				case_sensitive: { type: "boolean", default: false },
				words: { type: "boolean", default: false, description: "Whole-word match (wraps pattern with \\b boundaries)" },
				invert: { type: "boolean", default: false, description: "Return lines that do NOT match (per-line invert, not per-tiddler)" },
				filter: { type: "string", description: "TW filter scope; default '[all[tiddlers]!is[system]]' or '[all[tiddlers]]' when include_system" },
				include_system: { type: "boolean", default: false },
				max_lines_per_tiddler: { type: "number", default: 10 },
				max_lines_total: { type: "number", default: 200 },
				snippet_cap: { type: "number", default: 200, description: "Per-line display cap; longer lines windowed around the match. Hash always derives from the full line." },
				context: { type: "number", default: 0, description: "Context lines before AND after each match (grep -C). Caps count matches only -- context lines are free." },
				context_before: { type: "number", description: "Override context for BEFORE only (grep -B). Defaults to value of context." },
				context_after: { type: "number", description: "Override context for AFTER only (grep -A). Defaults to value of context." }
			},
			required: ["pattern"]
		}
	},
	{
		name: "list_tiddlers",
		description: "Namespace tree summary of tiddler titles with common-prefix header. flat:true returns newline-separated titles instead. Filter flags mutually exclusive, priority: plugin > overwrittenShadows > tag > includeSystem (only highest applies). limit caps result (default 100, truncation footer when exceeded).",
		inputSchema: {
			type: "object",
			properties: {
				tag: { type: "string", description: "Filter by tag" },
				plugin: { type: "string", description: "List plugin subtiddlers" },
				overwrittenShadows: { type: "boolean", default: false },
				limit: { type: "number", default: 100 },
				includeSystem: { type: "boolean", default: false },
				flat: { type: "boolean", default: false, description: "Return raw newline-separated titles instead of namespace tree summary" }
			},
			required: []
		}
	},
	{
		name: "reload_tiddlers",
		description: "Re-read tiddlers from disk; reports diff vs last call (first call may show large initial set). scope='shadows': refreshes non-JS plugin subtiddlers (doc/wikitext/CSS) — does NOT re-execute plugin JS. For JS in tw-mcp plugin use reload_mcp_modules. Refreshes $:/config/OriginalTiddlerPaths when retain-original-tiddler-path is set.",
		inputSchema: {
			type: "object",
			properties: {
				scope: { type: "string", enum: ["tiddlers", "shadows", "all"], default: "tiddlers", description: "tiddlers = edition tiddlers on disk (default). shadows = re-register plugins and re-unpack shadow tiddlers from in-memory plugin JSON (does NOT re-read plugin folders from disk). all = both." }
			},
			required: []
		}
	},
	{
		name: "inspect_tw",
		description: "Read-only $tw navigation. path: dot-path (e.g. 'wiki.boot.wikiPath'); blocks __proto__/constructor/prototype. Objects → keys+types+values, depth auto-reduces above 10KB. Functions without call → signature + source (truncated; fullSource:true for full). Functions with call → invoked, gated by read-only safe-list ($tw.wiki.* getters/filters, $tw.utils.*, heartbeats; full list in error). Writes go through put_tiddler/edit_tiddler/delete_tiddler. Auto-resolve: object path + call[0]=methodName rewrites to path.method(...rest) before safe-list.",
		inputSchema: {
			type: "object",
			properties: {
				path: { type: "string", default: "", description: "Dot path (e.g. 'wiki', 'boot.wikiPath')" },
				call: { type: "array", items: { type: "string" }, description: "Call function with args" },
				depth: { type: "number", default: 1 },
				fullSource: { type: "boolean", default: false },
				exclude: { type: "array", items: { type: "string" }, description: "Keys to skip" }
			},
			required: []
		}
	},
	{
		name: "inspect_scope",
		description: "Variable scope at a source position. tiddler+charPos OR text+charPos. charPos = char offset into wikitext text field, NOT line number — p= from inspect_pos is lines including header, must be converted via source text. Output: per-var line w/ kind prefix (widget/fn/proc/macro/def/var), name, params, value (≤70 chars), source. Sections: local scope, used globals (parse-tree refs + transitive macro body expansion), other globals (all:true). match: requires named vars to equal given values — disambiguates sibling widgets sharing parseTreeNode.start (repeating lists). renderContext: 'isolated' (default), 'viewtemplate' (tiddler-render context), 'root' (PageTemplate context).",
		inputSchema: {
			type: "object",
			properties: {
				tiddler: { type: "string", description: "Tiddler title" },
				charPos: { type: "number", description: "Character position in text field" },
				text: { type: "string", description: "Wikitext instead of tiddler" },
				context: { type: "string", description: "Context tiddler" },
				match: { type: "object", description: "Match widget by variable values", additionalProperties: { type: "string" } },
				filter: { type: "string", description: "Substring filter" },
				limit: { type: "number", default: 20 },
				all: { type: "boolean", default: false, description: "Include unused globals" },
				renderContext: { type: "string", enum: ["isolated", "viewtemplate", "root"], default: "isolated" }
			},
			required: []
		}
	}
];

var writeTools = [
	{
		name: "put_tiddler",
		description: "Create or update tiddler, persists to disk. overwrite=true replaces existing. WITHOUT overwrite: existing-title silently creates duplicate with uniquified title (e.g. 'MyTiddler 1') — does NOT error. Check response title; use overwrite=true or edit_tiddler when updating.",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", maxLength: 1024, description: "Tiddler title (max 1024 chars)" },
				fields: { type: "object", description: "Tiddler fields (text, tags, type, etc.)", additionalProperties: true },
				overwrite: { type: "boolean", default: false }
			},
			required: ["title", "fields"]
		}
	},
	{
		name: "edit_tiddler",
		description: "Edit tiddler text and/or fields. Text edits via LINE#HASH anchors (e.g. '5#AB'); anchors come from get_tiddler. Stale anchors → HashlineMismatchError lists fresh anchors for retry. Fields via set_fields/delete_fields. One call covers both.",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", maxLength: 1024, description: "Tiddler title (max 1024 chars)" },
				edits: {
					type: "array",
					description: "Text line edits using hashline anchors (optional if only changing fields)",
					items: {
						type: "object",
						properties: {
							op: { type: "string", enum: ["replace_line", "replace_range", "append_at", "prepend_at"] },
							pos: { type: "string", description: "LINE#HASH anchor (e.g. '5#AB')" },
							end: { type: "string", description: "End anchor for replace_range" },
							lines: { type: "array", items: { type: "string" }, description: "New lines to insert/replace" }
						},
						required: ["op", "lines"]
					}
				},
				set_fields: { type: "object", description: "Fields to add or update (key: value). Does not affect text field — use edits for text.", additionalProperties: true },
				delete_fields: { type: "array", items: { type: "string" }, description: "Field names to remove" }
			},
			required: ["title"]
		}
	},
	{
		name: "delete_tiddler",
		description: "Delete tiddler + .tid file. Shadow-only tiddlers (plugin-provided): removed from store only, no file touched, reappear on reload. Path gated by allowed-paths.",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", maxLength: 1024, description: "Tiddler title (max 1024 chars)" }
			},
			required: ["title"]
		}
	},
	{
		name: "rename_tiddler",
		description: "Rename a tiddler: updates title field + moves on-disk file via FSP rules + removes the old file (and .meta sidecar if present). Cross-references inside other tiddlers are NOT touched (use replace_in_tiddlers). preserve_timestamps=true (default) keeps the original `modified` field; set false to bump it. WITHOUT overwrite: errors if `to` exists. Refuses bundled plugin/theme/language tiddlers and .multids entries.",
		inputSchema: {
			type: "object",
			properties: {
				from: { type: "string", maxLength: 1024, description: "Current tiddler title" },
				to: { type: "string", maxLength: 1024, description: "New tiddler title" },
				overwrite: { type: "boolean", default: false, description: "If true, replace an existing tiddler at `to`" },
				preserve_timestamps: { type: "boolean", default: true, description: "If true (default), keep the original `modified` field. Set false to set `modified` to now." }
			},
			required: ["from", "to"]
		}
	},
	{
		name: "replace_in_tiddlers",
		description: "Bulk per-line find+replace across tiddlers. Dry-run output (dry_run=true default): title header, '  - <n>#<hash>: before' then '  + <n>#<hash>: after' per change (text field anchor; other fields 'field:L<n>'). Footer 'DRY RUN: N replacements across M tiddlers' + 'Call again with dry_run=false to apply'. Apply output: '<N> tiddlers modified, <M> replacements' + failure list. Empty: '(no matches)'. Defaults: fields=['text','caption','list','tags'] (tags/list serialised via stringifyList, parsed back on write), case-insensitive literal. Rules applied sequentially per line. Regex compiled with g flag (all matches per line); replacement supports JS backrefs $1..$9, $&, $$. Caps: max_tiddlers=100, max_replacements_total=1000.",
		inputSchema: {
			type: "object",
			properties: {
				rules: {
					type: "array",
					description: "Array of {pattern, replacement, regexp?, case_sensitive?, words?} objects",
					items: {
						type: "object",
						properties: {
							pattern: { type: "string", description: "Find pattern (literal by default; regex when regexp=true)" },
							replacement: { type: "string", description: "Replacement string. When regexp=true supports $1..$9, $&, $$." },
							regexp: { type: "boolean", default: false },
							case_sensitive: { type: "boolean", default: false },
							words: { type: "boolean", default: false, description: "Wrap pattern with \\b boundaries" }
						},
						required: ["pattern", "replacement"]
					}
				},
				filter: { type: "string", description: "TW filter scope; default '[all[tiddlers]!is[system]]' or '[all[tiddlers]]' when include_system" },
				include_system: { type: "boolean", default: false },
				fields: { type: "array", items: { type: "string" }, description: "Fields to scan; default ['text','caption','list','tags']" },
				dry_run: { type: "boolean", default: true, description: "Preview only; nothing written. Set false to apply." },
				max_tiddlers: { type: "number", default: 100 },
				max_replacements_total: { type: "number", default: 1000 }
			},
			required: ["rules"]
		}
	},
	{
		name: "reload_mcp_modules",
		description: "Hot-reload tw-mcp plugin. Re-reads plugin folder, refreshes ALL subtiddlers (JS + non-JS doc/wikitext/CSS), re-executes JS modules. Non-JS applies immediately; JS modules apply on next tool call. Excludes mcp.js/mcp-lib.js/shared.js/filesystem.js (hold live state — need server restart).",
		inputSchema: {
			type: "object",
			properties: {
				skip_disk_reload: { type: "boolean", default: false, description: "Skip the $tw.loadPlugin step. Use only when the wiki store already has fresh plugin source (e.g., after a manual reload_tiddlers)." }
			},
			required: []
		}
	},
	{
		name: "resave_tiddler",
		description: "Rewrite a tiddler's .tid file using current FileSystemPaths. Relocates the file if path rules changed. Preserves modified/modifier by default. Refuses on shadow-only, plugin/theme/language, or .multids-bundled tiddlers.",
		inputSchema: {
			type: "object",
			properties: {
				title: { type: "string", maxLength: 1024, description: "Tiddler title (max 1024 chars)" },
				preserve_timestamps: { type: "boolean", default: true, description: "Keep modified/modifier unchanged (default). Set false to stamp current time and user." },
				strip_redundant: { type: "boolean", default: true, description: "Drop 'revision' and drop 'type' when it equals text/vnd.tiddlywiki (default)." },
				dry_run: { type: "boolean", default: false, description: "Report old/new path and fields that would be stripped; do not write." }
			},
			required: ["title"]
		}
	},
	{
		name: "save_wiki_folder",
		description: "Export wiki to folder. filter selects tiddlers (default '[all[tiddlers]]'). explodePlugins='yes' (default): plugins as exploded subtiddler folders; 'no': single .json bundles. Path gated by allowed-paths.",
		inputSchema: {
			type: "object",
			properties: {
				path: { type: "string", description: "Output directory" },
				filter: { type: "string", default: "[all[tiddlers]]" },
				explodePlugins: { type: "string", enum: ["yes", "no"], default: "yes" }
			},
			required: ["path"]
		}
	},
	{
		name: "build_wiki",
		description: "Render wiki as single HTML. Silently overwrites output, creates parent dirs. template = renderable tiddler (default '$:/core/save/all'); invalid template → empty output, not error. Verify result.",
		inputSchema: {
			type: "object",
			properties: {
				output: { type: "string", description: "Output file path" },
				template: { type: "string", default: "$:/core/save/all" }
			},
			required: ["output"]
		}
	},
	{
		name: "import_html_wiki",
		description: "Stage a single-file HTML wiki for import. Loads tiddlers from the file into memory, classifies them, proposes FileSystemPaths rules, and writes the staged analysis to $:/temp/mcp/html-import. Nothing is written to disk yet — call extract_html_wiki to commit. Refuses if the wiki folder is already populated or another import is already pending.",
		inputSchema: {
			type: "object",
			properties: {
				path: { type: "string", description: "Path to the .html single-file wiki to import. Paths with `.`-prefixed directory or filename segments (e.g. `.ssh/`, `.config/`, `.env`) are refused as a defence-in-depth against reading hidden config." }
			},
			required: ["path"]
		}
	},
	{
		name: "extract_html_wiki",
		description: "Commit a previously staged HTML wiki import (see import_html_wiki) to disk as .tid files. Reads $:/config/FileSystemPaths from the wiki by default; the user can edit it in the browser before this call. Optionally override the rules via fileSystemPaths.",
		inputSchema: {
			type: "object",
			properties: {
				fileSystemPaths: { type: "string", description: "Approved FileSystemPaths rules (one filter per line). If omitted, reads $:/config/FileSystemPaths from the wiki." }
			},
			required: []
		}
	},
	{
		name: "upload_file",
		description: "Upload base64 file to files/, create canonical tiddler. tags = TW-format STRING (e.g. 'foo [[bar baz]]'), NOT array. Writes binary file + .tid sidecar with _canonical_uri.",
		inputSchema: {
			type: "object",
			properties: {
				filename: { type: "string", description: "Filename (no path separators)" },
				data: { type: "string", description: "Base64 content" },
				type: { type: "string", description: "MIME type" },
				title: { type: "string", maxLength: 1024, description: "Tiddler title (max 1024 chars; defaults to filename)" },
				tags: { type: "string" },
				subfolder: { type: "string", description: "Subfolder in files/" }
			},
			required: ["filename", "data", "type"]
		}
	}
];

function getToolDefinitions(isReadonly) {
	if(isReadonly) {
		return readTools;
	}
	return readTools.concat(writeTools);
}

exports.readTools = readTools;
exports.writeTools = writeTools;
exports.getToolDefinitions = getToolDefinitions;
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/filters/search-lines.js":{"title":"$:/core/modules/commands/inspect/filters/search-lines.js","text":"/*\
title: $:/core/modules/commands/inspect/filters/search-lines.js
type: application/javascript
module-type: filteroperator

Per-line search across tiddler fields. Mirrors the double-suffix shape
of core `search`: [search-lines:<fields>:<flags>[pattern]].

Default field list: ["text"]. Default flags: case-insensitive literal.
Supported flags: casesensitive, regexp, words (wrap with \b boundaries),
invert (return lines that do NOT match).

Multi-operand context (mirrors core `range`'s operands handling):
  [search-lines[pattern]]              -- no context
  [search-lines[pattern],[N]]          -- N lines before AND after each match
  [search-lines[pattern],[B],[A]]      -- B lines before, A lines after

Output: one string per emitted line in the form
  <title>:<field>:L<line>: <line text>   for match lines
  <title>:<field>:c<line>: <line text>   for context lines (when context > 0)

Multiline fields (default split on /\r?\n/) produce one entry per emitted
line; single-line fields at most one (lineNumber = 1). Array-valued
fields (eg `tags`, `list`) are serialised via $tw.utils.stringifyList
before matching, so the .tid on-disk form is what gets scanned
(multi-word entries wrapped in `[[...]]`). Other non-string field values
are skipped. With context, overlapping windows from adjacent matches are
merged so each line is emitted at most once.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

exports["search-lines"] = function(source, operator, options) {
	var operand = operator.operand;
	if(!operand) return [];
	var fields = ["text"];
	var caseSensitive = false;
	var regexp = false;
	var words = false;
	var invert = false;
	if(operator.suffixes) {
		var suffixFields = operator.suffixes[0] || [];
		if(suffixFields.length > 0) {
			fields = suffixFields;
		}
		var flags = operator.suffixes[1] || [];
		caseSensitive = flags.indexOf("casesensitive") !== -1;
		regexp = flags.indexOf("regexp") !== -1;
		words = flags.indexOf("words") !== -1;
		invert = flags.indexOf("invert") !== -1;
	}
	// Multi-operand context: [pattern, before?, after?]. 1 operand = no context;
	// 2 = symmetric N; 3 = asymmetric.
	var parts = operator.operands || [operand];
	var contextBefore = 0;
	var contextAfter = 0;
	if(parts.length === 2) {
		contextBefore = contextAfter = parseInt(parts[1], 10) || 0;
	} else if(parts.length >= 3) {
		contextBefore = parseInt(parts[1], 10) || 0;
		contextAfter = parseInt(parts[2], 10) || 0;
	}
	if(contextBefore < 0) contextBefore = 0;
	if(contextAfter < 0) contextAfter = 0;
	var hasContext = (contextBefore > 0 || contextAfter > 0);
	var compiled = shared.compileSearchRegex({
		pattern: operand,
		regexp: regexp,
		words: words,
		caseSensitive: caseSensitive
	});
	if(compiled.error) return [];
	var matcher = compiled.matcher;
	var results = [];
	source(function(tiddler, title) {
		if(!tiddler) return;
		for(var fi = 0; fi < fields.length; fi++) {
			var field = fields[fi];
			var value = tiddler.fields[field];
			if(Array.isArray(value)) {
				// Match against the .tid on-disk serialisation so callers
				// see `[[Some tag]] Other` rather than the runtime array.
				value = $tw.utils.stringifyList(value);
			}
			if(typeof value !== "string") continue;
			var lines = value.split(/\r?\n/);
			// Pass 1: identify match lines (1-indexed).
			var matchSet = Object.create(null);
			var matchLines = [];
			for(var li = 0; li < lines.length; li++) {
				var matched = matcher.test(lines[li]);
				if(invert ? !matched : matched) {
					matchSet[li + 1] = true;
					matchLines.push(li + 1);
				}
			}
			if(matchLines.length === 0) continue;
			if(!hasContext) {
				for(var mi = 0; mi < matchLines.length; mi++) {
					var ln = matchLines[mi];
					results.push(title + ":" + field + ":L" + ln + ": " + lines[ln - 1]);
				}
				continue;
			}
			// Pass 2: merged context ranges. Adjacent windows (within 1 line) merge.
			var ranges = [];
			for(var mi = 0; mi < matchLines.length; mi++) {
				var lo = Math.max(1, matchLines[mi] - contextBefore);
				var hi = Math.min(lines.length, matchLines[mi] + contextAfter);
				var last = ranges.length > 0 ? ranges[ranges.length - 1] : null;
				if(last && lo <= last.hi + 1) {
					last.hi = Math.max(last.hi, hi);
				} else {
					ranges.push({lo: lo, hi: hi});
				}
			}
			// Pass 3: emit each line in each range exactly once; marker depends on matchSet.
			for(var ri = 0; ri < ranges.length; ri++) {
				var r = ranges[ri];
				for(var ln = r.lo; ln <= r.hi; ln++) {
					var marker = matchSet[ln] ? "L" : "c";
					results.push(title + ":" + field + ":" + marker + ln + ": " + lines[ln - 1]);
				}
			}
		}
	});
	return results;
};
","type":"application/javascript","module-type":"filteroperator"},"$:/core/modules/commands/inspect/handlers/admin.js":{"title":"$:/core/modules/commands/inspect/handlers/admin.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/admin.js
type: application/javascript
module-type: library

MCP admin tools — currently: reload_mcp_modules for hot-reload of
plugin JS during development without restarting the server.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

var PLUGIN_NAME = "wikilabs/tw-mcp";
var PLUGIN_TITLE = "$:/plugins/" + PLUGIN_NAME;

// Modules that hold live state and cannot be reloaded without breaking
// running connections, init context, or change listeners.
var EXCLUDE_FROM_RELOAD = {
	"$:/core/modules/commands/mcp.js": "command module, runs once at boot",
	"$:/core/modules/commands/inspect/mcp-lib.js": "holds dispatcher, pipe server, stdin listener",
	"$:/core/modules/commands/inspect/handlers/shared.js": "holds readonlyMode and checkPathAllowed init context",
	"$:/core/modules/commands/inspect/handlers/filesystem.js": "holds reload_tiddlers change listener"
};

// Modules whose exports object identity must be preserved because
// mcp-lib.js captured a reference at require-time.
var PRESERVE_IDENTITY = {
	"$:/core/modules/commands/inspect/mcp-tools.js": true,
	"$:/core/modules/commands/inspect/mcp-handlers.js": true
};

// Map module-type to the $tw.Wiki.prototype cache TW builds lazily from
// $tw.modules.applyMethods. After a re-execute the cache holds stale
// function references; deleting the property forces the next
// getFilterOperators/getFilterRunPrefixes to rebuild from the now-fresh
// $tw.modules.types map.
var CACHE_INVALIDATE_MAP = {
	"filteroperator": "filterOperators",
	"filterrunprefix": "filterRunPrefixes"
};

function reloadInPlace(title, moduleType) {
	var text = $tw.wiki.getTiddlerText(title);
	if(!text) return { error: "no text in wiki store" };
	var info = $tw.modules.titles[title];
	if(!info) {
		// Module added since boot — register it now so it can be executed.
		$tw.modules.titles[title] = info = {
			moduleType: moduleType,
			definition: text,
			exports: undefined
		};
	}
	var oldExports = info.exports;
	info.definition = text;
	info.exports = undefined;
	try {
		$tw.modules.execute(title);
	} catch(e) {
		info.exports = oldExports;
		return { error: e.message };
	}
	var newExports = info.exports;
	if(PRESERVE_IDENTITY[title] && oldExports && typeof oldExports === "object" && oldExports !== newExports) {
		var k;
		for(k in oldExports) {
			if(!Object.prototype.hasOwnProperty.call(newExports, k)) {
				delete oldExports[k];
			}
		}
		for(k in newExports) {
			oldExports[k] = newExports[k];
		}
		info.exports = oldExports;
		newExports = oldExports;
	}
	// $tw.modules.types[<type>][<title>] holds the per-type exports map that
	// applyMethods walks. $tw.modules.execute updates info.exports but does NOT
	// touch the types map, so re-point it explicitly.
	if(moduleType && $tw.modules.types[moduleType]) {
		$tw.modules.types[moduleType][title] = newExports;
	}
	return { ok: true };
}

module.exports = {
	"reload_mcp_modules": function(args) {
		var denied = shared.checkWritable("reload_mcp_modules");
		if(denied) return denied;
		args = args || {};

		var messages = [];
		var reloaded = [];
		var skipped = [];
		var errors = [];

		// Phase 1: re-read plugin from disk so $tw.wiki has fresh subtiddler text.
		if(args.skip_disk_reload !== true) {
			try {
				var paths = $tw.getLibraryItemSearchPaths(
					$tw.config.pluginsPath,
					$tw.config.pluginsEnvVar
				);
				// Replicate $tw.loadPlugin without its bare addTiddler. Use
				// the syncer's storeTiddler instead, which adds the tiddler
				// AND updates the syncer's tiddlerInfo.changeCount to match
				// the bumped wiki.changeCount. The syncer's later sync check
				// (`wiki.getChangeCount > tiddlerInfo.changeCount`) is then
				// false, so the bundle is never persisted to the edition's
				// tiddlers/ folder. Fallback to addTiddler if no syncer is
				// active (eg headless `--build`).
				var pluginPath = $tw.findLibraryItem(PLUGIN_NAME, paths);
				if(!pluginPath) {
					return shared.errorResult("Plugin folder not found: " + PLUGIN_NAME);
				}
				var pluginFields = $tw.loadPluginFolder(pluginPath);
				if(!pluginFields) {
					return shared.errorResult("Failed to load plugin from folder: " + pluginPath);
				}
				if($tw.syncer) {
					$tw.syncer.storeTiddler(pluginFields);
				} else {
					$tw.wiki.addTiddler(pluginFields);
				}
				$tw.wiki.readPluginInfo();
				$tw.wiki.registerPluginTiddlers(null);
				$tw.wiki.unpackPluginTiddlers();
				messages.push("Plugin re-read from disk: " + PLUGIN_TITLE);
			} catch(e) {
				return shared.errorResult("Failed to re-read plugin from disk: " + e.message);
			}
		}

		// Phase 2: collect JS module titles inside the plugin.
		var pluginInfo = $tw.wiki.getPluginInfo(PLUGIN_TITLE);
		if(!pluginInfo || !pluginInfo.tiddlers) {
			return shared.errorResult("Plugin info not found: " + PLUGIN_TITLE);
		}
		var moduleTitles = [];
		Object.keys(pluginInfo.tiddlers).forEach(function(t) {
			var pt = pluginInfo.tiddlers[t];
			if(pt.type === "application/javascript" && pt["module-type"]) {
				moduleTitles.push(t);
			}
		});
		moduleTitles.sort();

		// Phase 3: reload each module, except excluded.
		var touchedTypes = Object.create(null);
		moduleTitles.forEach(function(title) {
			if(EXCLUDE_FROM_RELOAD[title]) {
				skipped.push(title + " (" + EXCLUDE_FROM_RELOAD[title] + ")");
				return;
			}
			var moduleType = pluginInfo.tiddlers[title]["module-type"];
			var result = reloadInPlace(title, moduleType);
			if(result.ok) {
				reloaded.push(title + (PRESERVE_IDENTITY[title] ? " [identity]" : ""));
				if(moduleType && CACHE_INVALIDATE_MAP[moduleType]) {
					touchedTypes[moduleType] = true;
				}
			} else {
				errors.push(title + ": " + result.error);
			}
		});

		// Phase 4: invalidate Wiki.prototype caches whose source module-types
		// were touched. The next getFilterOperators / getFilterRunPrefixes
		// call rebuilds from the now-fresh $tw.modules.types map.
		var invalidatedCaches = [];
		Object.keys(touchedTypes).forEach(function(mt) {
			var protoKey = CACHE_INVALIDATE_MAP[mt];
			if(Object.prototype.hasOwnProperty.call($tw.Wiki.prototype, protoKey)) {
				delete $tw.Wiki.prototype[protoKey];
				invalidatedCaches.push(protoKey + " (" + mt + ")");
			}
		});

		// Build output
		var out = messages.concat([
			"",
			"Reloaded " + reloaded.length + " module(s):"
		]).concat(reloaded.map(function(s) { return "  " + s; }));
		if(invalidatedCaches.length > 0) {
			out.push("");
			out.push("Invalidated " + invalidatedCaches.length + " Wiki.prototype cache(s):");
			invalidatedCaches.forEach(function(s) { out.push("  " + s); });
		}
		if(skipped.length > 0) {
			out.push("");
			out.push("Skipped " + skipped.length + " (excluded; restart required):");
			skipped.forEach(function(s) { out.push("  " + s); });
		}
		if(errors.length > 0) {
			out.push("");
			out.push("Errors (" + errors.length + "):");
			errors.forEach(function(s) { out.push("  " + s); });
		}
		return errors.length > 0
			? shared.errorResult(out.join("\n"))
			: shared.textResult(out.join("\n"));
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/crud/delete_tiddler.js":{"title":"$:/core/modules/commands/inspect/handlers/crud/delete_tiddler.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/crud/delete_tiddler.js
type: application/javascript
module-type: library

MCP tool handler: delete_tiddler — unlink the on-disk file (if any) then
remove the tiddler from the wiki store. Honours the allowed-paths gate.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"delete_tiddler": function(args) {
		var denied = shared.checkWritable("delete_tiddler");
		if(denied) return denied;
		var titleErr = shared.checkTitle(args.title, "delete_tiddler");
		if(titleErr) return titleErr;
		var checkPathAllowed = shared.getCheckPathAllowed();
		if(!$tw.wiki.tiddlerExists(args.title)) {
			return shared.errorResult("Tiddler not found: " + args.title);
		}
		var fileInfo = $tw.boot.files && $tw.boot.files[args.title];
		if(fileInfo) {
			var pathDenied = checkPathAllowed(fileInfo.filepath);
			if(pathDenied) return pathDenied;
			try {
				$tw.utils.deleteTiddlerFile(fileInfo, function(err) {
					if(err) {
						process.stderr.write("[tw-mcp] Error deleting file for tiddler: " + args.title + ": " + err + "\n");
					}
				});
				delete $tw.boot.files[args.title];
			} catch(e) {
				$tw.wiki.deleteTiddler(args.title);
				return shared.errorResult("Tiddler deleted from store but failed to remove file: " + e.message);
			}
		}
		$tw.wiki.deleteTiddler(args.title);
		return shared.textResult("Tiddler deleted: " + args.title);
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/crud/edit_tiddler.js":{"title":"$:/core/modules/commands/inspect/handlers/crud/edit_tiddler.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/crud/edit_tiddler.js
type: application/javascript
module-type: library

MCP tool handler: edit_tiddler — apply hashline-anchored edits to an
existing tiddler's text, optionally also setting/deleting other fields.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"edit_tiddler": function(args) {
		var denied = shared.checkWritable("edit_tiddler");
		if(denied) return denied;
		var titleErr = shared.checkTitle(args.title, "edit_tiddler");
		if(titleErr) return titleErr;
		var hashline = require("$:/core/modules/commands/inspect/hashline.js");
		var tiddler = $tw.wiki.getTiddler(args.title);
		if(!tiddler) {
			return shared.errorResult("Tiddler not found: " + args.title);
		}
		// Apply text edits if provided
		var newText = tiddler.fields.text || "";
		if(args.edits && args.edits.length > 0) {
			var edits = [];
			for(var i = 0; i < args.edits.length; i++) {
				var e = args.edits[i];
				var edit = { op: e.op, lines: e.lines || [] };
				if(e.pos) edit.pos = hashline.parseTag(e.pos);
				if(e.end) edit.end = hashline.parseTag(e.end);
				edits.push(edit);
			}
			try {
				var result = hashline.applyEdits(newText, edits);
				newText = result.text;
			} catch(e) {
				if(e.name === "HashlineMismatchError") {
					return shared.errorResult(e.message);
				}
				return shared.errorResult("Edit failed: " + e.message);
			}
		}
		// Build updated fields
		var updates = { text: newText };
		if(args.set_fields) {
			for(var key in args.set_fields) {
				if(key !== "text" && key !== "title") {
					updates[key] = args.set_fields[key];
				}
			}
		}
		var title = args.title;
		var modificationFields = $tw.wiki.getModificationFields();
		var newTiddler = new $tw.Tiddler(tiddler.fields, updates, modificationFields, { title: title });
		// Delete fields if requested
		if(args.delete_fields && args.delete_fields.length > 0) {
			var fieldsToKeep = {};
			for(var f in newTiddler.fields) {
				if(args.delete_fields.indexOf(f) === -1) {
					fieldsToKeep[f] = newTiddler.fields[f];
				}
			}
			newTiddler = new $tw.Tiddler(fieldsToKeep);
		}
		return shared.persistTiddler(newTiddler, title, "edited");
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/crud/get_tiddler.js":{"title":"$:/core/modules/commands/inspect/handlers/crud/get_tiddler.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/crud/get_tiddler.js
type: application/javascript
module-type: library

MCP tool handler: get_tiddler — single-tiddler read. Returns title-first
.tid/JSON/hashline forms; for plugin tiddlers shows the shadow-subtiddler
tree instead of the bundled text.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");
var crudShared = require("$:/core/modules/commands/inspect/handlers/crud/_shared.js");

module.exports = {
	"get_tiddler": function(args) {
		var tiddler = $tw.wiki.getTiddler(args.title);
		if(!tiddler) {
			return shared.errorResult("Tiddler not found: " + args.title);
		}
		if(shared.isPluginTiddler(tiddler)) {
			var pluginInfo = $tw.wiki.getPluginInfo(args.title);
			var shadowTitles = pluginInfo && pluginInfo.tiddlers ? Object.keys(pluginInfo.tiddlers).sort() : [];
			var readmeTitle = args.title + "/readme";
			var readmeIdx = shadowTitles.indexOf(readmeTitle);
			if(readmeIdx > 0) {
				shadowTitles.splice(readmeIdx, 1);
				shadowTitles.unshift(readmeTitle);
			}
			var output = crudShared.formatFieldsBlock(tiddler, {exclude: ["text"]}) + "\n\n" + shared.formatTitleTree(shadowTitles, "shadow tiddlers");
			return shared.textResult(output);
		}
		var includeText = !!args.detailed || !!args.lines;
		var unsafe = crudShared.hasUnsafeFields(tiddler);
		if(args.format === "json") {
			return shared.textResult(shared.jsonStringify(crudShared.extractFieldsObject(tiddler, {includeText: includeText})));
		} else if(args.format === "tid") {
			var output = crudShared.formatFieldsBlock(tiddler, {exclude: ["text"]});
			if(includeText && tiddler.fields.text !== undefined) {
				output += "\n\n" + tiddler.fields.text;
			}
			return shared.textResult(output);
		} else {
			// Default (hashline): title-first tid headers for safe fields, JSON for unsafe, hashlined text
			var header;
			if(unsafe) {
				header = shared.jsonStringify(crudShared.extractFieldsObject(tiddler, {includeText: false}));
			} else {
				header = crudShared.formatFieldsBlock(tiddler, {exclude: ["text"]});
			}
			var output = header;
			if(includeText && tiddler.fields.text !== undefined) {
				var hashline = require("$:/core/modules/commands/inspect/hashline.js");
				output += "\n\n" + hashline.formatHashLines(tiddler.fields.text);
			}
			return shared.textResult(output);
		}
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/crud/get_tiddlers.js":{"title":"$:/core/modules/commands/inspect/handlers/crud/get_tiddlers.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/crud/get_tiddlers.js
type: application/javascript
module-type: library

MCP tool handler: get_tiddlers — batch read by titles array. Text output
is CompoundTiddlers (blocks separated by `\n+\n`); JSON output is
{tiddlers, missing?, truncated?}.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");
var crudShared = require("$:/core/modules/commands/inspect/handlers/crud/_shared.js");

module.exports = {
	"get_tiddlers": function(args) {
		if(!args.titles || !Array.isArray(args.titles) || args.titles.length === 0) {
			return shared.errorResult("get_tiddlers: 'titles' must be a non-empty array");
		}
		// detailed defaults to TRUE: the batch use case is reading multiple
		// tiddlers' content; metadata-only batch is rare.
		var detailed = args.detailed !== false;
		// verbose=false (default) skips bookkeeping fields. Set true to include them.
		var verbose = !!args.verbose;
		var format = args.format || "hashline";
		var maxTiddlers = args.max_tiddlers || 50;
		var maxBytes = args.max_bytes || 50000;
		var SKIP_FIELDS = {created: 1, modified: 1, creator: 1, modifier: 1, revision: 1};
		var skipSet = verbose ? {} : SKIP_FIELDS;
		function renderText(tiddler, includeText) {
			var unsafe = crudShared.hasUnsafeFields(tiddler);
			var out;
			if(unsafe && format !== "tid") {
				out = shared.jsonStringify(crudShared.extractFieldsObject(tiddler, {skipSet: skipSet}));
			} else {
				out = crudShared.formatFieldsBlock(tiddler, {exclude: ["text"], skipSet: skipSet});
			}
			if(includeText && tiddler.fields.text !== undefined) {
				if(format === "hashline") {
					var hashlineLib = require("$:/core/modules/commands/inspect/hashline.js");
					out += "\n\n" + hashlineLib.formatHashLines(tiddler.fields.text);
				} else {
					out += "\n\n" + tiddler.fields.text;
				}
			}
			return out;
		}
		var entries = [];
		var missing = [];
		var totalBytes = 0;
		var truncated = 0;
		var inputTitles = args.titles;
		for(var i = 0; i < inputTitles.length; i++) {
			var title = inputTitles[i];
			if(entries.length >= maxTiddlers) {
				truncated = inputTitles.length - i;
				break;
			}
			var tiddler = $tw.wiki.getTiddler(title);
			if(!tiddler) {
				missing.push(title);
				continue;
			}
			var isPlugin = shared.isPluginTiddler(tiddler);
			// Plugins: fields-only (no shadow tree, no bundle text) regardless of detailed.
			var realDetailed = detailed && !isPlugin;
			var entry;
			var entryBytes;
			if(format === "json") {
				entry = { fields: crudShared.extractFieldsObject(tiddler, {includeText: realDetailed, skipSet: skipSet}) };
				entryBytes = JSON.stringify(entry.fields).length + 8;
			} else {
				entry = { content: renderText(tiddler, realDetailed) };
				entryBytes = entry.content.length + 4;
			}
			if(entries.length > 0 && totalBytes + entryBytes > maxBytes) {
				truncated = inputTitles.length - i;
				break;
			}
			totalBytes += entryBytes;
			entries.push(entry);
		}
		if(format === "json") {
			var result = { tiddlers: entries.map(function(e) { return e.fields; }) };
			if(missing.length > 0) result.missing = missing;
			if(truncated > 0) result.truncated = truncated;
			return shared.textResult(shared.jsonStringify(result));
		}
		// CompoundTiddlers (text/vnd.tiddlywiki-multiple): blocks separated by `\n+\n`.
		// Missing titles surface in a trailing `Missing: ...` line so the LLM can
		// retry/correct without misreading a stub block as real content.
		var blocks = entries.map(function(e) { return e.content.replace(/\n+$/, ""); });
		var output = blocks.join("\n+\n");
		var trailers = [];
		if(missing.length > 0) {
			trailers.push("Missing: " + missing.join(", "));
		}
		if(truncated > 0) {
			trailers.push("(" + truncated + " entries truncated; raise max_tiddlers or max_bytes)");
		}
		if(trailers.length > 0) {
			output += (output ? "\n\n" : "") + trailers.join("\n");
		}
		return shared.textResult(output);
	}
};
