title: $:/core/modules/commands/inspect/handlers/inspect/inspect_tree.js
type: application/javascript
module-type: library

MCP tool handler: inspect_tree — compact parse-tree summary with type
counts, link targets, and depth-bounded JSON dump of the widget tree.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"inspect_tree": function(args) {
		if(args.text && args.text.length > shared.MAX_TEXT_LENGTH) {
			return shared.errorResult( "Text too long (" + args.text.length + " chars). Maximum: " + shared.MAX_TEXT_LENGTH );
		}
		try {
			var rendered = shared.parseAndRender(args.text, args.type, args.context);
			if(!rendered) {
				return shared.errorResult( "No parser for text" );
			}
			var widgetNode = rendered.widgetNode;
			var wExcludeSet = shared.toSet(args.exclude);
			var wIncludeSet = shared.toSet(args.include);
			var maxDepth = args.depth || 3;
			var maxChildren = 10;
			var typeCounts = {};
			var linkTargets = [];
			var countTypes = function(wn) {
				var type = wn.parseTreeNode.type;
				typeCounts[type] = (typeCounts[type] || 0) + 1;
				if(type === "link" && wn.attributes && wn.attributes.to) {
					var target = wn.getAttribute("to");
					if(target && linkTargets.indexOf(target) === -1) {
						linkTargets.push(target);
					}
				}
				if(wn.children) {
					$tw.utils.each(wn.children, countTypes);
				}
			};
			countTypes(widgetNode);
			var copyNode = function(wn, rn, depth) {
				var type = wn.parseTreeNode.type;
				rn.type = type;
				if(type === "element") {
					rn.tag = wn.parseTreeNode.tag;
				} else if(type === "text") {
					var txt = wn.parseTreeNode.text;
					if(wIncludeSet.text) {
						// Cap inlined text at 2000 chars to prevent runaway output;
						// beyond that, show length + first/last 100 chars sample
						rn.text = txt.length > 2000
							? "…" + txt.length + ":" + txt.slice(0, 100) + "…" + txt.slice(-100)
							: txt;
					} else {
						rn.text = txt.length <= 10 ? txt : "…" + txt.length;
					}
				}
				if(wn.attributes && Object.keys(wn.attributes).length > 0) {
					rn.attributes = {};
					$tw.utils.each(wn.attributes, function(attr, attrName) {
						if(wExcludeSet[attrName]) return;
						rn.attributes[attrName] = wn.getAttribute(attrName);
					});
				}
				if(wn.children && wn.children.length > 0) {
					if(depth >= maxDepth) {
						rn.children = "{" + wn.children.length + " nodes}";
					} else {
						rn.children = [];
						var limit = Math.min(wn.children.length, maxChildren);
						for(var ci = 0; ci < limit; ci++) {
							var node = {};
							rn.children.push(node);
							copyNode(wn.children[ci], node, depth + 1);
						}
						if(wn.children.length > maxChildren) {
							rn.children.push("+" + (wn.children.length - maxChildren) + " more");
						}
					}
				}
			};
			var result = {};
			copyNode(widgetNode, result, 0);
			var summary = [];
			var sortedTypes = Object.keys(typeCounts).sort(function(a, b) { return typeCounts[b] - typeCounts[a]; });
			for(var si = 0; si < sortedTypes.length; si++) {
				summary.push(typeCounts[sortedTypes[si]] + " " + sortedTypes[si]);
			}
			var totalNodes = 0;
			for(var ti = 0; ti < sortedTypes.length; ti++) {
				totalNodes += typeCounts[sortedTypes[ti]];
			}
			var header = "Total: " + totalNodes + " nodes (full tree). Types: " + summary.join(", ") + "\n";
			if(linkTargets.length > 0) {
				header += "Links (" + linkTargets.length + "): " + linkTargets.join(", ") + "\n";
			}
			header += "(showing depth=" + maxDepth + ")\n";
			return shared.textResult( header + shared.jsonStringify(result) );
		} catch(e) {
			return shared.errorResult( "inspect_tree error: " + e.message );
		}
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/inspect/inspect_tw.js":{"title":"$:/core/modules/commands/inspect/handlers/inspect/inspect_tw.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/inspect/inspect_tw.js
type: application/javascript
module-type: library

MCP tool handler: inspect_tw — walk $tw object graph at a path,
optionally invoke safe read-only methods, and render values/functions
with depth-bounded output capped by character budget.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"inspect_tw": function(args) {
		var targetPath = (args.path || "").trim();
		var requestedDepth = args.depth || 1;
		var excludeSet = (args.exclude && args.exclude.length > 0) ? shared.toSet(args.exclude) : null;
		var target = $tw;
		var blockedSegments = {"__proto__": true, "constructor": true, "prototype": true};
		if(targetPath) {
			var segments = targetPath.split(".");
			for(var i = 0; i < segments.length; i++) {
				if(blockedSegments[segments[i]]) {
					return shared.errorResult( "Access to " + segments[i] + " is blocked for security" );
				}
				if(target === null || target === undefined) {
					return shared.errorResult( "$tw." + segments.slice(0, i).join(".") + " is " + String(target) );
				}
				if(typeof target !== "object" && typeof target !== "function") {
					return shared.errorResult( "$tw." + segments.slice(0, i).join(".") + " is " + typeof target );
				}
				target = target[segments[i]];
			}
		}
		var prefix = "$tw" + (targetPath ? "." + targetPath : "");
		if(target === null || target === undefined) {
			return shared.textResult( prefix + "=" + String(target) );
		}
		// Auto-resolve: path is an object (not function) + call provided + call[0] is a method name
		if(typeof target === "object" && target !== null && args.call && args.call.length > 0) {
			var methodName = args.call[0];
			if(typeof target[methodName] === "function") {
				var resolvedPath = targetPath + "." + methodName;
				var resolvedArgs = args.call.slice(1);
				return module.exports["inspect_tw"]({
					path: resolvedPath,
					call: resolvedArgs,
					depth: requestedDepth,
					exclude: args.exclude,
					fullSource: args.fullSource
				});
			} else {
				return shared.errorResult( prefix + " is not a function. '" + methodName + "' is " + typeof target[methodName] + " on this object. Did you mean path='" + targetPath + "." + methodName + "'?" );
			}
		}
		if(typeof target === "function") {
			if(args.call) {
				var safeCallFunctions = {
					"wiki.getTiddler": true,
					"wiki.getTiddlerText": true,
					"wiki.tiddlerExists": true,
					"wiki.isShadowTiddler": true,
					"wiki.getShadowSource": true,
					"wiki.filterTiddlers": true,
					"wiki.allTitles": true,
					"wiki.allShadowTitles": true,
					"wiki.getPluginInfo": true,
					"wiki.getPluginTypes": true,
					"wiki.getIndexer": true,
					"mcp.heartbeat": true,
					"httpServer.heartbeat": true
				};
				var isSafe = safeCallFunctions[targetPath] || targetPath.indexOf("utils.") === 0;
				if(!isSafe) {
					var safeList = Object.keys(safeCallFunctions).map(function(k) { return "$tw." + k; }).join(", ");
					return shared.errorResult( "call is only allowed on safe read-only functions: " + safeList + ", $tw.utils.*" );
				}
				var parent = $tw;
				if(targetPath) {
					var parentSegments = targetPath.split(".");
					parentSegments.pop();
					for(var pi = 0; pi < parentSegments.length; pi++) {
						parent = parent[parentSegments[pi]];
					}
				}
				try {
					target = target.apply(parent, args.call);
					prefix = prefix + "(" + args.call.map(function(a) { return JSON.stringify(a); }).join(",") + ")";
				} catch(callErr) {
					return shared.errorResult( prefix + " call error: " + callErr.message );
				}
			} else {
				var fnStr = Function.prototype.toString.call(target);
				var sigMatch = fnStr.match(/^(?:function\s*[^(]*)(\([^)]*\))/);
				var sig = sigMatch ? sigMatch[1] : "(" + (target.length || 0) + ")";
				var lines = [];
				lines.push("fn " + prefix + sig);
				lines = lines.concat(shared.formatFnSource(fnStr, "", !!args.fullSource));
				return shared.textResult( lines.join("\n") );
			}
		}
		if(typeof target !== "object") {
			return shared.textResult( prefix + "=" + String(target) );
		}
		var keys;
		try {
			keys = Object.keys(target);
		} catch(e) {
			return shared.errorResult( "Cannot enumerate " + prefix + ": " + e.message );
		}
		keys.sort();
		var availableDepth = shared.computeMaxDepth(target, 5);
		var MAX_RESULT_CHARS = 10000;
		var currentDepth = requestedDepth;
		var result, depthNote = "";
		while(currentDepth >= 0) {
			var lines = [];
			lines.push(prefix + " " + keys.length + "keys maxDepth=" + availableDepth);
			for(var k = 0; k < keys.length; k++) {
				if(excludeSet && excludeSet[keys[k]]) { continue; }
				try {
					lines = lines.concat(shared.inspectValue(target[keys[k]], keys[k], 0, currentDepth - 1, excludeSet));
				} catch(e) {
					lines.push(keys[k] + " !err");
				}
			}
			result = lines.join("\n");
			if(result.length <= MAX_RESULT_CHARS || currentDepth <= 0) {
				break;
			}
			currentDepth--;
		}
		if(currentDepth < requestedDepth) {
			depthNote = "⚠ depth reduced from " + requestedDepth + " to " + currentDepth + " (result exceeded " + MAX_RESULT_CHARS + " chars)\n";
		}
		return shared.textResult( depthNote + result );
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/inspect/_shared.js":{"title":"$:/core/modules/commands/inspect/handlers/inspect/_shared.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/inspect/_shared.js
type: application/javascript
module-type: library

Per-group helpers shared by the inspect/* handler files. Currently:

* patchSourceTitleTracking() — monkey-patches Widget.prototype.setVariable
  and ImportVariablesWidget.prototype.execute so that variables loaded via
  importvariables carry a `sourceTitle` property pointing at the tiddler
  that defined them. Used by inspect_pos (to attribute rendered DOM to
  its source) and inspect_scope (to classify variables as local vs
  imported). Returns a restore() callback that MUST be invoked in a
  finally block — otherwise the patches persist on the global widget
  prototypes and affect every subsequent render.

\*/

"use strict";

function patchSourceTitleTracking() {
	var Widget = require("$:/core/modules/widgets/widget.js").widget;
	var ImportVariablesWidget = require("$:/core/modules/widgets/importvariables.js").importvariables;
	// Tag each variable defined via setVariable() with its defining tiddler
	// when the caller passes options.sourceTitle.
	var origSetVariable = Widget.prototype.setVariable;
	Widget.prototype.setVariable = function(name, value, params, isMacroDefinition, options) {
		origSetVariable.call(this, name, value, params, isMacroDefinition, options);
		if(options && options.sourceTitle && this.variables[name]) {
			this.variables[name].sourceTitle = options.sourceTitle;
		}
	};
	// importvariables doesn't pass options.sourceTitle through setVariable, so
	// parse each imported tiddler ourselves, build a name → title map, and
	// assign sourceTitle on the variable instances after origExecute populated
	// them.
	var origImportExecute = ImportVariablesWidget.prototype.execute;
	ImportVariablesWidget.prototype.execute = function(tiddlerList) {
		origImportExecute.call(this, tiddlerList);
		var varSourceMap = Object.create(null);
		var self = this;
		$tw.utils.each(this.tiddlerList, function(title) {
			var parser = self.wiki.parseTiddler(title, {parseAsInline: true, configTrimWhiteSpace: false});
			if(parser) {
				var node = parser.tree[0];
				while(node && ["setvariable","set","parameters","void"].indexOf(node.type) !== -1) {
					if(node.attributes && node.attributes.name) {
						varSourceMap[node.attributes.name.value] = title;
					}
					node = node.children && node.children[0];
				}
			}
		});
		var ptr = this;
		while(ptr) {
			if(ptr.variables) {
				var ownKeys = Object.keys(ptr.variables);
				for(var ki = 0; ki < ownKeys.length; ki++) {
					var v = ptr.variables[ownKeys[ki]];
					if(v && !v.sourceTitle && varSourceMap[ownKeys[ki]]) {
						v.sourceTitle = varSourceMap[ownKeys[ki]];
					}
				}
			}
			ptr = (ptr.children && ptr.children.length === 1) ? ptr.children[0] : null;
		}
	};
	return function restore() {
		Widget.prototype.setVariable = origSetVariable;
		ImportVariablesWidget.prototype.execute = origImportExecute;
	};
}

exports.patchSourceTitleTracking = patchSourceTitleTracking;
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/query/get_wiki_info.js":{"title":"$:/core/modules/commands/inspect/handlers/query/get_wiki_info.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/query/get_wiki_info.js
type: application/javascript
module-type: library

MCP tool handler: get_wiki_info — wiki metadata (title, version, counts,
plugins, themes, settings) plus MCP role/PID and HTML-import status if
pending.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"get_wiki_info": function(args) {
		var plugins = $tw.wiki.filterTiddlers("[plugin-type[plugin]]");
		var themes = $tw.wiki.filterTiddlers("[plugin-type[theme]]");
		var languages = $tw.wiki.filterTiddlers("[plugin-type[language]]");
		var wikiTitle = $tw.wiki.renderText("text/plain", "text/vnd.tiddlywiki", $tw.wiki.getTiddlerText("$:/SiteTitle", "Untitled"));
		var wikiSubtitle = $tw.wiki.renderText("text/plain", "text/vnd.tiddlywiki", $tw.wiki.getTiddlerText("$:/SiteSubtitle", ""));
		var tiddlerCount = parseInt($tw.wiki.filterTiddlers("[!is[system]count[]]")[0]) || 0;
		var tagCount = parseInt($tw.wiki.filterTiddlers("[tags[]count[]]")[0]) || 0;
		var systemTiddlerCount = parseInt($tw.wiki.filterTiddlers("[is[system]count[]]")[0]) || 0;
		var shadowTiddlerCount = parseInt($tw.wiki.filterTiddlers("[all[shadows]count[]]")[0]) || 0;
		var overriddenShadowCount = parseInt($tw.wiki.filterTiddlers("[is[tiddler]is[shadow]count[]]")[0]) || 0;
		var settingsList = [
			{title: "$:/SiteTitle", prompt: "Title/Prompt"},
			{title: "$:/SiteSubtitle", prompt: "Subtitle/Prompt"},
			{title: "$:/status/UserName", prompt: "Username/Prompt"},
			{title: "$:/config/AnimationDuration", prompt: "AnimDuration/Prompt"},
			{title: "$:/DefaultTiddlers", prompt: "DefaultTiddlers/Prompt"},
			{title: "$:/language/DefaultNewTiddlerTitle", prompt: "NewTiddler/Title/Prompt"},
			{title: "$:/config/NewJournal/Title", prompt: "NewJournal/Title/Prompt"},
			{title: "$:/config/NewJournal/Text", prompt: "NewJournal/Text/Prompt"},
			{title: "$:/config/NewTiddler/Tags", prompt: "NewTiddler/Tags/Prompt"},
			{title: "$:/config/NewJournal/Tags", prompt: "NewJournal/Tags/Prompt"},
			{title: "$:/config/AutoFocus", prompt: "AutoFocus/Prompt"},
			{title: "$:/config/AutoFocusEdit", prompt: "AutoFocusEdit/Prompt"}
		];
		var lines = [];
		lines.push(wikiTitle + (wikiSubtitle ? " — " + wikiSubtitle : ""));
		lines.push("TiddlyWiki v" + $tw.version + (shared.isReadonly() ? " (readonly)" : ""));
		lines.push("");
		lines.push("Tiddlers: " + tiddlerCount + " | Tags: " + tagCount + " | System: " + systemTiddlerCount + " | Shadow: " + shadowTiddlerCount + " | Overridden: " + overriddenShadowCount);
		lines.push("Filesystem: " + (!!$tw.syncadaptor ? "yes" : "no") + (($tw.boot.wikiTiddlersPath) ? " (" + $tw.boot.wikiTiddlersPath + ")" : ""));
		if($tw.mcp) {
			lines.push("MCP: " + $tw.mcp.role + " v" + ($tw.mcp.version || "?") + " (PID " + $tw.mcp.pid + ")" + ($tw.mcp.label ? " @" + $tw.mcp.label : ""));
		}
		if($tw.httpServer) {
			var addr = $tw.httpServer.nodeServer && $tw.httpServer.nodeServer.address();
			lines.push("HTTP: " + (addr ? addr.address + ":" + addr.port : "not listening"));
		}
		if(plugins.length) {
			lines.push("Plugins:");
			$tw.utils.each(plugins, function(p) { lines.push("  " + p); });
		}
		if(themes.length) {
			lines.push("Themes:");
			$tw.utils.each(themes, function(t) { lines.push("  " + t); });
		}
		if(languages.length) {
			lines.push("Languages:");
			$tw.utils.each(languages, function(l) { lines.push("  " + l); });
		}
		// HTML import status
		var importTiddler = $tw.wiki.getTiddler("$:/temp/mcp/html-import");
		if(importTiddler) {
			var importStatus = importTiddler.fields.status;
			var sourceFile = importTiddler.fields["source-file"] || "unknown";
			var contentCount = importTiddler.fields["content-count"] || "?";
			if(importStatus === "pending") {
				lines.push("");
				lines.push("HTML Import: PENDING — " + contentCount + " tiddlers in memory from " + sourceFile);
				lines.push("  Read $:/temp/mcp/html-import for analysis and proposed FileSystemPaths");
				lines.push("  Use extract_html_wiki to write .tid files after review");
			} else if(importStatus === "extracted") {
				lines.push("");
				lines.push("HTML Import: extracted " + (importTiddler.fields["files-written"] || "?") + " files from " + sourceFile);
			}
		}
		lines.push("");
		lines.push("Settings:");
		$tw.utils.each(settingsList, function(entry) {
			var description = $tw.wiki.getTiddlerText("$:/language/ControlPanel/Basics/" + entry.prompt, "");
			var value = $tw.wiki.getTiddlerText(entry.title, "");
			if(value.indexOf("\n") !== -1) {
				lines.push("  " + entry.title + (description ? " (" + description + ")" : "") + ":");
				lines.push("    " + value.split("\n").join("\n    "));
			} else {
				lines.push("  " + entry.title + " = " + value + (description ? " (" + description + ")" : ""));
			}
		});
		return shared.textResult(lines.join("\n"));
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/query/list_tiddlers.js":{"title":"$:/core/modules/commands/inspect/handlers/query/list_tiddlers.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/query/list_tiddlers.js
type: application/javascript
module-type: library

MCP tool handler: list_tiddlers — convenience over run_filter for common
listing tasks (plugin contents, overridden shadows, tag, system inclusion).

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"list_tiddlers": function(args) {
		var filter;
		if(args.plugin) {
			filter = "[[" + shared.sanitiseFilterOperand(args.plugin) + "]plugintiddlers[]sort[title]]";
		} else if(args.overwrittenShadows) {
			filter = "[is[tiddler]is[shadow]sort[title]]";
		} else if(args.tag) {
			filter = "[tag[" + shared.sanitiseFilterOperand(args.tag) + "]]";
		} else if(args.includeSystem) {
			filter = "[all[tiddlers]sort[title]]";
		} else {
			filter = "[all[tiddlers]!is[system]sort[title]]";
		}
		var results = $tw.wiki.filterTiddlers(filter);
		var total = results.length;
		var limit = args.limit || 100;
		var truncated = total > limit;
		if(args.flat) {
			var flatList = truncated ? results.slice(0, limit) : results;
			var flatOut = flatList.join("\n");
			if(truncated) {
				flatOut += "\n\n(" + total + " total, showing first " + limit + ")";
			}
			return shared.textResult(flatOut);
		}
		if(total > 100 && !args.limit) {
			return shared.textResult(shared.formatTitleTree(results, "tiddlers", total));
		}
		if(truncated) {
			results = results.slice(0, limit);
		}
		var output = shared.formatTitleTree(results);
		if(truncated) {
			output += "\n\n(" + total + " total, showing first " + limit + ")";
		}
		return shared.textResult(output);
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/query/run_filter.js":{"title":"$:/core/modules/commands/inspect/handlers/query/run_filter.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/query/run_filter.js
type: application/javascript
module-type: library

MCP tool handler: run_filter — evaluate a TW filter expression and
return matching titles, one per line. Caps at 500 results.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

module.exports = {
	"run_filter": function(args) {
		if(args.filter && args.filter.length > shared.MAX_FILTER_LENGTH) {
			return shared.errorResult("Filter too long (" + args.filter.length + " chars). Maximum: " + shared.MAX_FILTER_LENGTH);
		}
		try {
			var results = $tw.wiki.filterTiddlers(args.filter);
			var maxResults = 500;
			var total = results.length;
			var output;
			if(total === 0) {
				output = "(no results)";
			} else if(total <= maxResults) {
				output = results.join("\n");
			} else {
				output = results.slice(0, maxResults).join("\n") + "\n\n(" + total + " total, showing first " + maxResults + ")";
			}
			return shared.textResult(output);
		} catch(e) {
			return shared.errorResult("Filter error: " + e.message );
		}
	}
};
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/inspect/handlers/query/search_lines.js":{"title":"$:/core/modules/commands/inspect/handlers/query/search_lines.js","text":"/*\
title: $:/core/modules/commands/inspect/handlers/query/search_lines.js
type: application/javascript
module-type: library

MCP tool handler: search_lines — per-line search via the search-lines
filter operator; groups by title+field, splits into ranges by line-number
gaps, formats with hashline anchors + optional context (`- ` prefix) and
`--` separators between non-adjacent ranges.

\*/

"use strict";

var shared = require("$:/core/modules/commands/inspect/handlers/shared.js");

// `probe` is a non-global RegExp built once by the caller (the global flag
// of the search matcher would carry lastIndex across calls and skip matches).
function windowSnippet(line, probe, cap) {
	if(line.length <= cap) return line;
	var m = probe.exec(line);
	if(!m) return line.slice(0, cap) + "...";
	var matchStart = m.index;
	var matchLen = m[0].length;
	var remaining = cap - matchLen;
	if(remaining < 20) {
		return "..." + line.slice(matchStart, matchStart + cap - 6) + "...";
	}
	var half = Math.floor(remaining / 2);
	var sliceStart = Math.max(0, matchStart - half);
	var sliceEnd = Math.min(line.length, sliceStart + cap);
	if(sliceEnd === line.length) {
		sliceStart = Math.max(0, line.length - cap);
	}
	var snippet = line.slice(sliceStart, sliceEnd);
	if(sliceStart > 0) snippet = "..." + snippet;
	if(sliceEnd < line.length) snippet = snippet + "...";
	return snippet;
}

module.exports = {
	"search_lines": function(args) {
		if(!args.pattern) {
			return shared.errorResult("search_lines: missing required argument 'pattern'");
		}
		if(args.pattern.length > shared.MAX_FILTER_LENGTH) {
			return shared.errorResult("Pattern too long (max " + shared.MAX_FILTER_LENGTH + ")");
		}
		var fields = (args.fields && args.fields.length > 0) ? args.fields : ["text"];
		var caseSensitive = !!args.case_sensitive;
		var regexp = !!args.regexp;
		var words = !!args.words;
		var invert = !!args.invert;
		var contextN = Math.max(0, args.context | 0);
		var contextBefore = (args.context_before !== undefined) ? Math.max(0, args.context_before | 0) : contextN;
		var contextAfter = (args.context_after !== undefined) ? Math.max(0, args.context_after | 0) : contextN;
		var hasContext = (contextBefore > 0 || contextAfter > 0);
		var compiled = shared.compileSearchRegex({
			pattern: args.pattern,
			regexp: regexp,
			words: words,
			caseSensitive: caseSensitive
		});
		if(compiled.error) {
			return shared.errorResult("Invalid regex: " + compiled.error);
		}
		var matcher = compiled.matcher;
		// Non-global clone for snippet probing (windowSnippet's exec must not
		// advance the shared matcher's lastIndex). Built once instead of per
		// match line.
		var snippetProbe = new RegExp(matcher.source, matcher.flags.replace("g", ""));
		var scoped = shared.scopedTitles(args);
		if(scoped.errorResult) return scoped.errorResult;
		var sourceTitles = scoped.titles;
		var source = function(callback) {
			sourceTitles.forEach(function(title) {
				callback($tw.wiki.getTiddler(title), title);
			});
		};
		// Invoke the filter operator directly so the operand can contain any character
		// (calling via filterTiddlers would require escaping `]` etc).
		var searchLinesOp = require("$:/core/modules/commands/inspect/filters/search-lines.js");
		var flagList = [];
		if(caseSensitive) flagList.push("casesensitive");
		if(regexp) flagList.push("regexp");
		if(words) flagList.push("words");
		if(invert) flagList.push("invert");
		var operands = [args.pattern];
		if(hasContext) {
			operands.push(String(contextBefore));
			operands.push(String(contextAfter));
		}
		var operator = {
			operand: args.pattern,
			operands: operands,
			suffixes: [fields, flagList]
		};
		var rawResults = searchLinesOp["search-lines"](source, operator, {wiki: $tw.wiki});
		if(rawResults.length === 0) {
			return shared.textResult("(no matches)");
		}
		var hashline = require("$:/core/modules/commands/inspect/hashline.js");
		// Operator emits 'L<n>' for match lines and 'c<n>' for context lines.
		var lineRegex = /^(.*?):([^:]+):([Lc])(\d+):\s?([\s\S]*)$/;
		var maxPerTiddler = args.max_lines_per_tiddler || 10;
		var maxTotal = args.max_lines_total || 200;
		var snippetCap = args.snippet_cap || 200;
		// Pass 1: parse the flat operator output into typed entries.
		var entries = [];
		for(var i = 0; i < rawResults.length; i++) {
			var m = lineRegex.exec(rawResults[i]);
			if(!m) continue;
			entries.push({
				title: m[1],
				field: m[2],
				isMatch: m[3] === "L",
				line: parseInt(m[4], 10),
				text: m[5]
			});
		}
		// Pass 2: group by title (preserve first-seen order); within title, group by field.
		var titleOrder = [];
		var titleBuckets = Object.create(null);
		for(var i = 0; i < entries.length; i++) {
			var e = entries[i];
			if(!titleBuckets[e.title]) {
				titleBuckets[e.title] = { fieldOrder: [], fieldEntries: Object.create(null) };
				titleOrder.push(e.title);
			}
			var bucket = titleBuckets[e.title];
			if(!bucket.fieldEntries[e.field]) {
				bucket.fieldOrder.push(e.field);
				bucket.fieldEntries[e.field] = [];
			}
			bucket.fieldEntries[e.field].push(e);
		}
		// Pass 3: format. Detect range boundaries by line-number gaps within (title, field).
		// Apply caps on MATCH count: an entire range is accepted or dropped atomically.
		// Display: existing match form for matches, '- ' prefix for context, '  --'
		// separator between non-adjacent ranges (only when context is requested -- without
		// context every match looks like its own 1-line range, and separators would noise).
		function formatLine(field, lineNum, lineText, isMatch) {
			var displayText = windowSnippet(lineText, snippetProbe, snippetCap);
			var prefix = (field === "text")
				? hashline.formatLineTag(lineNum, lineText)
				: field + ":L" + lineNum;
			return (isMatch ? "  " : "  - ") + prefix + ": " + displayText;
		}
		var blocks = [];
		var totalMatches = 0;
		var truncated = false;
		for(var ti = 0; ti < titleOrder.length; ti++) {
			if(truncated) break;
			var t = titleOrder[ti];
			var bucket = titleBuckets[t];
			var perTiddler = 0;
			var titleLines = [];
			var titleHasContent = false;
			for(var fi = 0; fi < bucket.fieldOrder.length && !truncated; fi++) {
				var fName = bucket.fieldOrder[fi];
				var fEntries = bucket.fieldEntries[fName];
				// Split into ranges by line-number gap.
				var ranges = [];
				var current = null;
				for(var ei = 0; ei < fEntries.length; ei++) {
					var entry = fEntries[ei];
					if(current === null || entry.line !== current[current.length - 1].line + 1) {
						if(current) ranges.push(current);
						current = [];
					}
					current.push(entry);
				}
				if(current) ranges.push(current);
				// Accept whole ranges until a cap would be exceeded.
				for(var ri = 0; ri < ranges.length; ri++) {
					var range = ranges[ri];
					var rangeMatches = 0;
					for(var rei = 0; rei < range.length; rei++) {
						if(range[rei].isMatch) rangeMatches++;
					}
					if(perTiddler + rangeMatches > maxPerTiddler) {
						truncated = true;
						break;
					}
					if(totalMatches + rangeMatches > maxTotal) {
						truncated = true;
						break;
					}
					if(titleHasContent && hasContext) {
						titleLines.push("  --");
					}
					for(var rei = 0; rei < range.length; rei++) {
						var re = range[rei];
						titleLines.push(formatLine(re.field, re.line, re.text, re.isMatch));
					}
					perTiddler += rangeMatches;
					totalMatches += rangeMatches;
					titleHasContent = true;
				}
			}
			if(titleLines.length > 0) {
				blocks.push(t + "\n" + titleLines.join("\n"));
			}
		}
		if(blocks.length === 0) {
			return shared.textResult("(no matches)");
		}
		var output = blocks.join("\n\n");
		output += "\n\n" + totalMatches + " line" + (totalMatches !== 1 ? "s" : "") +
			" matched in " + blocks.length + " tiddler" + (blocks.length !== 1 ? "s" : "");
		if(truncated) {
			output += "\n(truncated at " + maxTotal + " matches; narrow filter or raise max_lines_total)";
		}
		return shared.textResult(output);
	}
};
