title: $:/core/modules/commands/inspect/handlers/shared.js
type: application/javascript
module-type: library

Shared utilities and state for MCP tool handlers.

\*/

"use strict";

var fs = require("fs"),
	path = require("path");

// TW core's $tw.utils.getParser always returns *some* parser: if the
// requested MIME type has no registered parser, it falls back to
// text/vnd.tiddlywiki. That makes the fallback invisible to MCP callers
// who passed an explicit `type` arg expecting it to be honoured. This
// helper returns a short caller-facing note (or null) so handlers can
// prepend it to their output and surface the fallback explicitly.
function parserFallbackWarning(userType) {
	if(!userType) return null;
	if($tw.Wiki.parsers[userType]) return null;
	var ext = $tw.utils.getFileExtensionInfo(userType);
	if(ext && $tw.Wiki.parsers[ext.type]) return null;
	return "Note: type '" + userType + "' is not registered; rendered as text/vnd.tiddlywiki.";
}

// Source position format — must match $:/plugins/tiddlywiki/sourcepos/utils.js
var SOURCE_POS_SEPARATOR = " @ ";
function formatSourcePos(startLine, endLine, title) {
	var pos = (startLine === endLine) ? "L" + startLine : "L" + startLine + "-L" + endLine;
	if(title) pos += SOURCE_POS_SEPARATOR + title;
	return pos;
}

// Module-level state, set via init()
var readonlyMode = false;
var checkPathAllowed = null;

function init(context) {
	readonlyMode = context.readonlyMode;
	checkPathAllowed = context.checkPathAllowed;
}

function checkWritable(toolName) {
	if(readonlyMode) {
		return errorResult("Tool '" + toolName + "' is disabled in readonly mode");
	}
	return null;
}

function isReadonly() {
	return readonlyMode;
}

function getCheckPathAllowed() {
	return checkPathAllowed;
}

var MAX_FILTER_LENGTH = 10000;
var MAX_TEXT_LENGTH = 500000;
// Tiddler titles are stored in $tw.wiki's title index, broadcast in SSE event
// payloads, and serialised as filesystem paths. Without a cap, a malicious MCP
// client could OOM the process with multi-megabyte titles. 1024 is generous --
// real titles are rarely over ~100 chars.
var MAX_TITLE_LENGTH = 1024;

// Validate a tiddler title supplied by the MCP client. Only fires on string
// inputs that exceed the cap -- non-string / undefined / empty are left for
// the handler's own missing-arg logic to surface.
function checkTitle(title, toolName) {
	if(typeof title === "string" && title.length > MAX_TITLE_LENGTH) {
		return errorResult("Tool '" + toolName + "': title too long (" + title.length + " chars, max " + MAX_TITLE_LENGTH + ")");
	}
	return null;
}

// Build namespace tree from sorted titles.
function buildTree(titles, maxDepth, _indent) {
	if(!titles.length) return { prefix: "", tree: "" };
	if(maxDepth === undefined) maxDepth = 1;
	_indent = _indent || "";
	var commonParts = titles[0].split("/");
	for(var i = 1; i < titles.length; i++) {
		var parts = titles[i].split("/");
		var match = 0;
		for(var j = 0; j < Math.min(commonParts.length, parts.length); j++) {
			if(parts[j] === commonParts[j]) { match++; } else { break; }
		}
		commonParts = commonParts.slice(0, match);
		if(!commonParts.length) break;
	}
	var commonPrefix = commonParts.length >= 2 ? commonParts.join("/") + "/" : "";
	var prefixDepth = commonPrefix ? commonParts.length : 0;
	var groupDepth = prefixDepth > 0 ? prefixDepth + 1 : 2;
	var groups = {};
	var groupOrder = [];
	for(var i = 0; i < titles.length; i++) {
		var parts = titles[i].split("/");
		var key;
		if(parts.length <= groupDepth) {
			key = commonPrefix ? titles[i].slice(commonPrefix.length) || titles[i] : titles[i];
		} else {
			key = parts.slice(prefixDepth, groupDepth).join("/") + "/";
		}
		if(!groups[key]) {
			groups[key] = [];
			groupOrder.push(key);
		}
		groups[key].push(titles[i]);
	}
	groupOrder.sort();
	var lines = [];
	for(var k = 0; k < groupOrder.length; k++) {
		var key = groupOrder[k];
		var items = groups[key];
		if(key.slice(-1) === "/" && maxDepth > 1 && items.length > 1) {
			var sub = buildTree(items, maxDepth - 1, _indent + "\t");
			var relPrefix = sub.prefix.slice(commonPrefix.length);
			lines.push(_indent + "\t" + relPrefix + " (" + items.length + ")");
			if(sub.tree) lines.push(sub.tree);
		} else if(key.slice(-1) === "/") {
			lines.push(_indent + "\t" + key + " (" + items.length + ")");
		} else {
			lines.push(_indent + "\t" + key);
		}
	}
	return { prefix: commonPrefix, tree: lines.join("\n") };
}

// Build a title tree and prepend a "<prefix> ... N <label>" summary line
// when the result has a common prefix. label defaults to "tiddlers"; count
// defaults to titles.length. Wraps buildTree() for the common case where
// callers want a single string they can interpolate directly.
function formatTitleTree(titles, label, count) {
	var ns = buildTree(titles);
	var n = (count !== undefined) ? count : titles.length;
	var lbl = label || "tiddlers";
	// Header is emitted when:
	//   - there's a common prefix to lead with, OR
	//   - the caller passed an explicit count (signals "show this number"), OR
	//   - the caller passed a non-default label (signals "tell the user what
	//     these entries are").
	// Without this, list_tiddlers' count-summary branch silently dropped the
	// grand total, and get_tiddler's plugin shadow tree dropped its label.
	var header = "";
	if(ns.prefix) {
		header = ns.prefix + " ... " + n + " " + lbl + "\n";
	} else if(count !== undefined || (label && label !== "tiddlers")) {
		header = n + " " + lbl + "\n";
	}
	return header + ns.tree;
}

// Shared parse+render helper
// Parse text and build the import-variables-wrapped tree + widget options.
// Returns { parser, wrappedTree, widgetOptions } or null if parsing fails.
// Used directly by inspect_pos (which needs to mutate the widget between
// makeWidget and render); for the common case prefer parseAndRender.
function buildWrappedTree(text, inputType, context, extraVariables) {
	var parser = $tw.wiki.parseText(inputType || "text/vnd.tiddlywiki", text, { parseAsInline: false });
	if(!parser) return null;
	var importFilter = $tw.wiki.getTiddlerText("$:/core/config/GlobalImportFilter");
	var wrappedTree = {tree: [{
		type: "importvariables",
		attributes: {
			filter: { name: "filter", type: "string", value: importFilter }
		},
		isBlock: false,
		children: parser.tree
	}]};
	var widgetOptions = { document: $tw.fakeDocument };
	var vars = {};
	if(context) {
		vars.currentTiddler = context;
	}
	if(extraVariables) {
		var extraKeys = Object.keys(extraVariables);
		for(var ei = 0; ei < extraKeys.length; ei++) {
			vars[extraKeys[ei]] = extraVariables[extraKeys[ei]];
		}
	}
	if(Object.keys(vars).length > 0) {
		widgetOptions.variables = vars;
	}
	return { parser: parser, wrappedTree: wrappedTree, widgetOptions: widgetOptions };
}

function parseAndRender(text, inputType, context, extraVariables) {
	var built = buildWrappedTree(text, inputType, context, extraVariables);
	if(!built) return null;
	var widgetNode = $tw.wiki.makeWidget(built.wrappedTree, built.widgetOptions);
	var container = $tw.fakeDocument.createElement("div");
	widgetNode.render(container, null);
	return {
		parser: built.parser,
		wrappedTree: built.wrappedTree,
		widgetOptions: built.widgetOptions,
		widgetNode: widgetNode,
		container: container
	};
}

// Inspect helpers

function formatFnSource(fnStr, pad, full) {
	var srcLines = fnStr.split("\n");
	var out = [];
	if(full) {
		for(var f = 0; f < srcLines.length; f++) {
			out.push(pad + "  " + srcLines[f].replace(/\t/g, "  "));
		}
	} else {
		var head = srcLines.slice(0, 5);
		for(var h = 0; h < head.length; h++) {
			out.push(pad + "  " + head[h].replace(/\t/g, "  "));
		}
		var rest = srcLines.length - 5;
		if(rest > 0) {
			out.push(pad + "  ..." + rest + " more lines");
		}
	}
	return out;
}

function inspectValue(val, key, indent, depthLeft, excludeSet) {
	var lines = [];
	var pad = "";
	for(var p = 0; p < indent; p++) { pad += "  "; }
	var type = typeof val;
	if(val === null || val === undefined) {
		lines.push(pad + key + " " + String(val));
	} else if(type === "string") {
		var display = val.length > 70 ? val.substring(0, 70) + "~" : val;
		lines.push(pad + key + " s:" + val.length + " " + display.replace(/\n/g, "\\n"));
	} else if(type === "number" || type === "boolean") {
		lines.push(pad + key + "=" + String(val));
	} else if(val instanceof Date || Object.prototype.toString.call(val) === "[object Date]" || ($tw.utils.isDate && $tw.utils.isDate(val))) {
		lines.push(pad + key + " date:" + val.toISOString());
	} else if(type === "function") {
		var fnStr = Function.prototype.toString.call(val);
		var sigMatch = fnStr.match(/^(?:function\s*[^(]*)(\([^)]*\))/);
		var sig = sigMatch ? sigMatch[1] : "(" + (val.length || 0) + ")";
		lines.push(pad + "fn " + key + sig);
		if(depthLeft > 0) {
			lines = lines.concat(formatFnSource(fnStr, pad));
		}
	} else if(Array.isArray(val)) {
		lines.push(pad + key + " [" + val.length + "]");
		if(depthLeft > 0 && val.length > 0) {
			var arrLimit = Math.min(val.length, 20);
			for(var a = 0; a < arrLimit; a++) {
				try {
					lines = lines.concat(inspectValue(val[a], "[" + a + "]", indent + 1, 0, excludeSet));
				} catch(e) {
					lines.push(pad + "  [" + a + "] !err");
				}
			}
			if(val.length > arrLimit) {
				lines.push(pad + "  ..." + (val.length - arrLimit) + " more");
			}
		}
	} else {
		var childKeys;
		try {
			childKeys = Object.keys(val);
		} catch(e2) {
			lines.push(pad + key + " {?}");
			return lines;
		}
		lines.push(pad + key + " {" + childKeys.length + "}");
		if(depthLeft > 0) {
			childKeys.sort();
			for(var c = 0; c < childKeys.length; c++) {
				if(excludeSet && excludeSet[childKeys[c]]) { continue; }
				try {
					lines = lines.concat(inspectValue(val[childKeys[c]], childKeys[c], indent + 1, depthLeft - 1, excludeSet));
				} catch(e3) {
					lines.push(pad + "  " + childKeys[c] + " !err");
				}
			}
		}
	}
	return lines;
}

function computeMaxDepth(obj, limit) {
	if(limit <= 0 || obj === null || obj === undefined) {
		return 0;
	}
	var type = typeof obj;
	if(type !== "object" && type !== "function") {
		return 0;
	}
	var keys;
	try {
		keys = Object.keys(obj);
	} catch(e) {
		return 0;
	}
	if(keys.length === 0) {
		return 0;
	}
	var deepest = 0;
	for(var i = 0; i < keys.length && i < 50; i++) {
		try {
			var child = obj[keys[i]];
			if(child !== null && child !== undefined && (typeof child === "object" || typeof child === "function")) {
				var d = 1 + computeMaxDepth(child, limit - 1);
				if(d > deepest) {
					deepest = d;
				}
			}
		} catch(e) {
			// skip
		}
	}
	return deepest;
}

// --- Response helpers ---

function textResult(msg) {
	return { content: [{ type: "text", text: msg }] };
}

function errorResult(msg) {
	return { isError: true, content: [{ type: "text", text: msg }] };
}

// Resolve a filter-scope from MCP args and run it. Both replace_in_tiddlers
// and search_lines need the same default ('[all[tiddlers]!is[system]]' or
// '[all[tiddlers]]' when include_system) and the same try/catch wrap.
// Returns {titles, errorResult}. Caller pattern:
//   var scoped = shared.scopedTitles(args);
//   if(scoped.errorResult) return scoped.errorResult;
//   var titles = scoped.titles;
function scopedTitles(args) {
	var scope = args.filter || (args.include_system ? "[all[tiddlers]]" : "[all[tiddlers]!is[system]]");
	try {
		return { titles: $tw.wiki.filterTiddlers(scope) };
	} catch(e) {
		return { errorResult: errorResult("Filter error: " + e.message) };
	}
}

// Strip characters that would break filter-operand embedding when an arg
// is interpolated into a TW filter expression like `[tag[...]]`. The strip
// list covers the TW-core forbidden title chars (`|`, `[`, `]`, `{`, `}`)
// plus `<` / `>` for paranoia. Used by list_tiddlers (plugin, tag args)
// and render_tiddler (title arg).
function sanitiseFilterOperand(value) {
	if(typeof value !== "string") return value;
	return value.replace(/[|\[\]{}<>]/g, "");
}

// Serialise a rendered container element according to the requested output
// type. Mirrors the type enum used by render_tiddler, render_field, and
// render_text. text/html uses the fakedom's safe innerHTML serialiser.
function containerToText(container, outputType) {
	if(outputType === "text/html") return container.innerHTML;
	if(outputType === "text/plain-formatted") return container.formattedTextContent;
	return container.textContent;
}

// Build a `$tw.Tiddler` from existing fields, optionally re-stamping
// modified/modifier. When preserveTimestamps is true the source fields'
// created/modified are kept; otherwise they're refreshed to "now". `extra`
// is an optional object merged after the modification fields (used by
// rename_tiddler to set the new title).
function buildTiddlerWithTimestamps(fields, extra, preserveTimestamps) {
	if(preserveTimestamps) {
		return extra ? new $tw.Tiddler(fields, extra) : new $tw.Tiddler(fields);
	}
	var modFields = $tw.wiki.getModificationFields();
	return extra ? new $tw.Tiddler(fields, modFields, extra) : new $tw.Tiddler(fields, modFields);
}

// Stringify a value with the project-standard indent (`jsonSpaces` preference).
// Centralised so a future switch to compact JSON (token thrift) is one edit.
function jsonStringify(value) {
	return JSON.stringify(value, null, $tw.config.preferences.jsonSpaces);
}

// Convert an array of strings into a {key: true} lookup map. Returns an
// empty object when arr is falsy. Used by inspect_tree, inspect_tw, and
// render_text for exclude/include args.
function toSet(arr) {
	var set = {};
	if(arr) {
		for(var i = 0; i < arr.length; i++) {
			set[arr[i]] = true;
		}
	}
	return set;
}

// Is the tiddler a plugin/theme/language/etc bundle? Returns true if any
// `plugin-type` field value is present.
function isPluginTiddler(tiddler) {
	return !!(tiddler && tiddler.fields["plugin-type"]);
}

// Return the `plugin-type` field value (eg "plugin", "theme", "language",
// "import") or null when the tiddler isn't a plugin bundle.
function getPluginKind(tiddler) {
	return (tiddler && tiddler.fields["plugin-type"]) || null;
}

// Guard against operating on bundled plugin / theme / language tiddlers.
// These are constructed from their shadow source tiddlers and shouldn't be
// rewritten directly. Returns an errorResult to short-circuit the caller,
// or null when the tiddler is safe to operate on.
function checkNotBundled(tiddler, action, title) {
	var kind = getPluginKind(tiddler);
	if(kind === "plugin" || kind === "theme" || kind === "language") {
		return errorResult("Refusing to " + action + " bundled " + kind + ": " + title);
	}
	return null;
}

// Read $:/config/FileSystemPaths and $:/config/FileSystemExtensions, return
// as filter arrays. options.filterBlank drops blank/whitespace-only lines
// from pathFilters (extFilters is never blank-filtered in current callers).
// Returns {pathFilters, extFilters}, either may be undefined if the config
// tiddler is missing/empty.
function loadFspFseFilters(options) {
	options = options || {};
	var fspText = $tw.wiki.getTiddlerText("$:/config/FileSystemPaths", "");
	var fseText = $tw.wiki.getTiddlerText("$:/config/FileSystemExtensions", "");
	var pathFilters = fspText ? fspText.split("\n") : undefined;
	var extFilters = fseText ? fseText.split("\n") : undefined;
	if(options.filterBlank && pathFilters) {
		pathFilters = pathFilters.filter(function(l) { return l.trim(); });
	}
	return { pathFilters: pathFilters, extFilters: extFilters };
}

// Compile a search pattern (literal by default; regex when options.regexp).
// Common across search_lines (query.js), the search-lines filter operator,
// and replace_in_tiddlers (crud.js).
// Options:
//   pattern (required)
//   regexp: treat as JS regex (default false)
//   words: wrap matcher with \b boundaries (default false)
//   caseSensitive: default false (case-insensitive 'i' flag)
//   global: include 'g' flag (replace_in_tiddlers wants this for multi-match-per-line)
// Returns {matcher} on success, {error: <message>} on bad pattern.
function compileSearchRegex(options) {
	var pattern = options.pattern;
	try {
		var src = options.regexp ? pattern : pattern.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
		if(options.words) {
			src = "\\b(?:" + src + ")\\b";
		}
		var flags = "";
		if(options.global) flags += "g";
		if(!options.caseSensitive) flags += "i";
		return { matcher: new RegExp(src, flags) };
	} catch(e) {
		return { error: e.message };
	}
}

// --- File persistence helper (used by put_tiddler and edit_tiddler) ---

function verifyOnDisk(fileInfo, title) {
	try {
		if(fileInfo.hasMetaFile) {
			// Binary tiddler: title header is in the .meta sidecar; the body
			// file holds binary content (eg SVG XML, PNG bytes) and only needs
			// to exist non-empty.
			var metaContent = fs.readFileSync(fileInfo.filepath + ".meta", "utf8");
			if(metaContent.length === 0 || metaContent.indexOf("title: " + title) === -1) {
				return false;
			}
			return fs.existsSync(fileInfo.filepath) && fs.statSync(fileInfo.filepath).size > 0;
		}
		// Self-contained .tid: title header is in the body file.
		var content = fs.readFileSync(fileInfo.filepath, "utf8");
		return content.length > 0 && content.indexOf("title: " + title) !== -1;
	} catch(e) {
		return false;
	}
}

function persistTiddler(tiddler, title, action) {
	var checkPathAllowed = getCheckPathAllowed();
	if(!$tw.boot.wikiTiddlersPath) {
		// No wiki tiddlers path — still add to in-memory store.
		$tw.wiki.addTiddler(tiddler);
		return textResult("Tiddler " + action + " in store only (no wiki tiddlers path): " + title);
	}
	// Capture pre-call state for rollback. Snapshot boot.files entry by
	// shallow copy because the in-place mutation later would otherwise
	// destroy the original.
	var oldTiddler = $tw.wiki.getTiddler(title);
	var oldFileInfoSrc = $tw.boot.files[title];
	var oldFileInfo = oldFileInfoSrc ? $tw.utils.extend({}, oldFileInfoSrc) : null;
	function rollbackWikiState() {
		if(oldTiddler) {
			$tw.wiki.addTiddler(oldTiddler);
		} else {
			$tw.wiki.deleteTiddler(title);
		}
		if(oldFileInfo) {
			$tw.boot.files[title] = oldFileInfo;
		} else {
			delete $tw.boot.files[title];
		}
	}
	try {
		var filters = loadFspFseFilters();
		var pathFilters = filters.pathFilters;
		var extFilters = filters.extFilters;
		// Add to wiki FIRST so FSP filters can evaluate against this
		// tiddler's tags / fields. Computing fileInfo with the tiddler
		// not yet in the wiki makes [tag[X]] rules return empty for
		// this title; the tiddler then lands at the default path and
		// the syncer's nextTick (after addTiddler) recomputes with the
		// tag visible and writes a SECOND copy at the tag-determined
		// path. Net result: duplicate files for the same tiddler when
		// FSP uses tag-based rules.
		$tw.wiki.addTiddler(tiddler);
		// Compute filepath. overwrite:true so the uniquifier doesn't pick
		// a _1/_2 suffix for an existing target file.
		var baseFileInfo = oldFileInfo ? $tw.utils.extend({}, oldFileInfo) : {};
		baseFileInfo.overwrite = true;
		var fileInfo = $tw.utils.generateTiddlerFileInfo(tiddler, {
			directory: $tw.boot.wikiTiddlersPath,
			pathFilters: pathFilters,
			extFilters: extFilters,
			wiki: $tw.wiki,
			fileInfo: baseFileInfo
		});
		var pathDenied = checkPathAllowed(fileInfo.filepath);
		if(pathDenied) {
			rollbackWikiState();
			return pathDenied;
		}
		// Pre-seed $tw.boot.files so the syncadaptor, when its nextTick
		// fires after addTiddler, sees our resolved fileInfo and writes
		// to the same path (idempotent overwrite).
		$tw.boot.files[title] = fileInfo;
		// Synchronous write — deterministic result, independent of the syncer.
		$tw.utils.saveTiddlerToFileSync(tiddler, fileInfo);
		// Verify: read back the file and confirm the title header is present.
		// Catches both 0-byte writes and content that gets truncated by a racing
		// async syncadaptor save before we report success. For binary tiddlers
		// (hasMetaFile=true) the title header lives in the `.meta` sidecar; the
		// body file holds binary content and only needs to exist non-empty.
		var verified = verifyOnDisk(fileInfo, title);
		if(!verified) {
			// One retry: write again. The syncer only fires once per addTiddler,
			// so a second sync write is not racing with another async save.
			try { $tw.utils.saveTiddlerToFileSync(tiddler, fileInfo); } catch(e) {}
			verified = verifyOnDisk(fileInfo, title);
		}
		if(!verified) {
			// Roll back: remove the new file(s) and restore wiki state.
			try { fs.unlinkSync(fileInfo.filepath); } catch(e) {}
			if(fileInfo.hasMetaFile) {
				try { fs.unlinkSync(fileInfo.filepath + ".meta"); } catch(e) {}
			}
			rollbackWikiState();
			return errorResult("Tiddler " + action + " failed: verification failed for " + fileInfo.filepath + ". Store and filesystem rolled back.");
		}
		return textResult("Tiddler " + action + ": " + title + " -> " + fileInfo.filepath);
	} catch(e) {
		rollbackWikiState();
		return errorResult("Tiddler " + action + " in store but failed to save to disk: " + e.message);
	}
}

// Add a tiddler without triggering a syncer save. `Syncer.storeTiddler`
// syncs `tiddlerInfo[title].changeCount` with the post-add wiki value
// so the comparator skips it. Use when we persist the .tid ourselves
// (upload_file, extract_html_wiki) or for derived / disk-sourced
// tiddlers (OTP refresh, reload_tiddlers). Takes plain fields.
function addToWikiSilently(tiddlerFields) {
	if($tw.syncer) {
		$tw.syncer.storeTiddler(tiddlerFields);
	} else {
		$tw.wiki.addTiddler(tiddlerFields);
	}
}

exports.init = init;
exports.checkWritable = checkWritable;
exports.isReadonly = isReadonly;
exports.getCheckPathAllowed = getCheckPathAllowed;
exports.buildTree = buildTree;
exports.formatTitleTree = formatTitleTree;
exports.parseAndRender = parseAndRender;
exports.buildWrappedTree = buildWrappedTree;
exports.formatSourcePos = formatSourcePos;
exports.formatFnSource = formatFnSource;
exports.inspectValue = inspectValue;
exports.computeMaxDepth = computeMaxDepth;
exports.MAX_FILTER_LENGTH = MAX_FILTER_LENGTH;
exports.MAX_TEXT_LENGTH = MAX_TEXT_LENGTH;
exports.MAX_TITLE_LENGTH = MAX_TITLE_LENGTH;
exports.checkTitle = checkTitle;
exports.textResult = textResult;
exports.errorResult = errorResult;
exports.scopedTitles = scopedTitles;
exports.compileSearchRegex = compileSearchRegex;
exports.loadFspFseFilters = loadFspFseFilters;
exports.checkNotBundled = checkNotBundled;
exports.isPluginTiddler = isPluginTiddler;
exports.getPluginKind = getPluginKind;
exports.toSet = toSet;
exports.containerToText = containerToText;
exports.sanitiseFilterOperand = sanitiseFilterOperand;
exports.jsonStringify = jsonStringify;
exports.buildTiddlerWithTimestamps = buildTiddlerWithTimestamps;
exports.persistTiddler = persistTiddler;
exports.addToWikiSilently = addToWikiSilently;
exports.SOURCE_POS_SEPARATOR = SOURCE_POS_SEPARATOR;
exports.parserFallbackWarning = parserFallbackWarning;
","type":"application/javascript","module-type":"library"},"$:/core/modules/commands/mcp.js":{"title":"$:/core/modules/commands/mcp.js","text":"/*\
title: $:/core/modules/commands/mcp.js
type: application/javascript
module-type: command

MCP (Model Context Protocol) server for TiddlyWiki.
Exposes wiki tools to Claude CLI and other MCP clients via stdio.

Usage (readonly by default):
  tiddlywiki ./wiki --mcp [label=<name>] [allowed-paths=<paths>]
  tiddlywiki ./wiki --mcp rw [label=<name>] [allowed-paths=<paths>]
  tiddlywiki ./wiki --mcp rw listen [port=<n>] [host=<h>] [label=<name>] ...
  tiddlywiki ./wiki --mcp rw sse    [port=<n>] [host=<h>] [label=<name>] ...

Single-file wiki workflow (runtime tools):
  Start a normal --mcp rw listen server against an empty wiki folder, then
  call import_html_wiki(path) to stage an HTML wiki for review and
  extract_html_wiki() to commit it to disk.

When "listen" is specified, an HTTP server is started in the same process
before the MCP server, so browser edits and MCP tool calls share one $tw.wiki.
All --listen parameters (port, host, credentials, tls-*, etc.) are accepted.

When "sse" is specified, "listen" is implied AND the Server-Sent Events
endpoint at GET /events is enabled. Browsers that load this plugin will
receive per-tiddler change notifications instead of polling for the full
tiddler list every 60s — see $:/plugins/wikilabs/tw-mcp/sse/ for the
client-side adaptor and bootstrap.
If both "sse" and "listen" are given, sse wins (no error).

\*/

"use strict";

var startMCPServer = require("$:/core/modules/commands/inspect/mcp-lib.js").startMCPServer;
var Server = require("$:/core/modules/server/server.js").Server;

exports.info = {
	name: "mcp",
	synchronous: true
};

var Command = function(params, commander, callback) {
	this.params = params;
	this.commander = commander;
	this.callback = callback;
};

Command.prototype.execute = function() {
	var options = { readonly: true }; // readonly by default
	var listenMode = false;
	var sseMode = false;
	var listenParams = {};
	for(var i = 0; i < this.params.length; i++) {
		var param = this.params[i];
		if(param === "readonly") {
			options.readonly = true;
		} else if(param === "rw" || param === "readwrite") {
			options.readonly = false;
		} else if(param === "listen") {
			listenMode = true;
		} else if(param === "sse") {
			listenMode = true;
			sseMode = true;
		} else if(param.indexOf("allowed-paths=") === 0) {
			options.allowedPaths = param.slice("allowed-paths=".length).split(",");
		} else if(param.indexOf("label=") === 0) {
			options.label = param.slice("label=".length);
		} else if(param.indexOf("=") !== -1) {
			// Named parameter — forward to listen server if in listen mode
			var eq = param.indexOf("=");
			listenParams[param.slice(0, eq)] = param.slice(eq + 1);
		}
	}
	// Load the filesystem plugin if not already present (needed for disk persistence)
	if(!options.readonly && !$tw.wiki.getTiddler("$:/plugins/tiddlywiki/filesystem")) {
		$tw.loadPlugins(["tiddlywiki/filesystem"], $tw.config.pluginsPath, $tw.config.pluginsEnvVar);
		$tw.wiki.registerPluginTiddlers("plugin");
		$tw.wiki.unpackPluginTiddlers();
	}
	// Start HTTP server if listen mode is enabled
	if(listenMode) {
		var mcpLib = require("$:/core/modules/commands/inspect/mcp-lib.js");
		var discovery = mcpLib.readDiscoveryFile();
		if(discovery && discovery.listen) {
			console.error("Primary already serves HTTP — skipping local HTTP server");
		} else {
			if(!$tw.boot.wikiTiddlersPath) {
				$tw.utils.warning("Warning: Wiki folder '" + $tw.boot.wikiPath + "' does not exist or is missing a tiddlywiki.info file");
			}
			var server = new Server({
				wiki: this.commander.wiki,
				variables: listenParams
			});
			var nodeServer = server.listen();
			$tw.httpServer = {
				server: server,
				nodeServer: nodeServer,
				heartbeat: function() {
					return {
						listening: nodeServer.listening,
						address: nodeServer.address()
					};
				}
			};
			$tw.hooks.invokeHook("th-server-command-post-start", server, nodeServer, "tiddlywiki");
		}
	}
	startMCPServer(options);
	// SSE init must run after startMCPServer because that resets $tw.mcp.
	// Only enable when this process owns the HTTP server (i.e. listenMode succeeded
	// and we did not fall through to "Primary already serves HTTP" — guarded by $tw.httpServer).
	if(sseMode && $tw.httpServer) {
		var sseLib = require("$:/core/modules/server/sse-broadcaster.js");
		sseLib.initialize(this.commander.wiki);
		// Signal browser-side bootstrap that --mcp sse is active so it can
		// take over the syncadaptor; without this, the SSE adaptor stays
		// dormant and tiddlyweb's polling adaptor is used.
		// Marker lives under $:/status/ so the default SyncFilter excludes it
		// from disk persistence (otherwise a subsequent start without --mcp sse
		// would still see the stale "yes" loaded from .tid)
		this.commander.wiki.addTiddler({
			title: "$:/status/wikilabs/tw-mcp/sse-server-active",
			text: "yes"
		});
		console.error("SSE enabled at GET /events");
	}
	return null;
};

exports.Command = Command;
","type":"application/javascript","module-type":"command"},"$:/plugins/wikilabs/tw-mcp/history":{"title":"$:/plugins/wikilabs/tw-mcp/history","text":"V 0.13.35 - 2026.05.12

* `upload_file` now rejects payloads larger than 50 MB before allocating the decoded buffer, matching the limit already enforced by the `tw-upload` CLI helper.

V 0.13.34 - 2026.05.12

* `list_tiddlers` now accepts a `flat: true` argument that returns newline-separated titles instead of the namespace tree summary.

V 0.13.33 - 2026.05.12

* `inspect_scope` now classifies imported variables (those defined in tiddlers brought in via `importvariables`, e.g. TW's page macros) correctly. The "— used globals" and "— other globals" sections of the output now populate as documented, and each imported variable surfaces with its source tiddler (`@$:/core/macros/...`).

V 0.13.32 - 2026.05.12

* `render_text` now warns the caller when their `type` argument isn't a recognised parser type, instead of silently treating the input as wikitext.
* `list_tiddlers` now shows a total count when many results are returned, and `get_tiddler` labels a plugin's subtiddler list as "shadow tiddlers".
* `inspect_scope` now correctly classifies `\procedure` variables as `proc` (they were previously shown as `def`).

V 0.13.31 - 2026.05.12

* Excluded the `sidecar/` directory from the plugin's loaded tiddler set, removing a stray `tw-upload.js` entry from the subtiddler list.

V 0.13.30 - 2026.05.12

* Internal code restructure (no user-visible change). The four `inspect_*` tool handlers now live in separate files under `handlers/inspect/`, one file per tool, instead of being bundled into a single 700-line module.
* The eight CRUD tool handlers (`get_tiddler`, `get_tiddlers`, `put_tiddler`, `edit_tiddler`, `resave_tiddler`, `rename_tiddler`, `replace_in_tiddlers`, `delete_tiddler`) now live in separate files under `handlers/crud/`, with the five module-level helpers in a per-group `_shared.js`.
* The four `query` tool handlers (`run_filter`, `get_wiki_info`, `list_tiddlers`, `search_lines`) and three `render` tool handlers (`render_tiddler`, `render_field`, `render_text`) now live in separate per-tool files under `handlers/query/` and `handlers/render/`. All MCP tool handlers are now one-tool-per-file.

V 0.13.27 - 2026.05.12

* Final pass of internal code cleanup, no user-visible change. As a small robustness improvement, the change log used by `reload_tiddlers` is now capped at 1000 entries (oldest dropped on overflow) so it can't grow unbounded between reloads.

V 0.13.26 - 2026.05.12

* More internal code cleanup, no user-visible change. Small correctness improvement: the title/tag/plugin sanitisation now also strips `|`, matching the TiddlyWiki core rule that forbids `|` in tiddler titles.

V 0.13.25 - 2026.05.12

* Internal code cleanup (no user-visible change). Five small pieces of logic that were duplicated across the MCP read, write, search, and find-and-replace tools are now single shared helpers. The plugin behaves identically; future fixes and tweaks to these shared behaviours land in one place instead of needing to be repeated in several handlers.

V 0.13.24 - 2026.05.12

* `get_tiddler` now puts `title:` first in text formats and at the start of the JSON object, matching v0.13.23 `get_tiddlers`. Both tools share a single `formatFieldsBlock` / `extractFieldsObject` helper.

V 0.13.23 - 2026.05.12

* New `get_tiddlers` MCP tool: batch fetch by titles array. Text output is CompoundTiddlers (`text/vnd.tiddlywiki-multiple`); JSON is `{tiddlers, missing?, truncated?}`. Defaults `detailed=true`, bookkeeping fields skipped (set `verbose=true` to include).

V 0.13.22 - 2026.05.12

* New `replace_in_tiddlers` MCP tool: bulk find+replace across many tiddlers in one call. Multiple `{pattern, replacement}` rules per call, per-rule `regexp`/`case_sensitive`/`words` flags, replacement supports JS backrefs (`$1..$9`, `$&`). Default fields scan `text`, `caption`, `list`, `tags` (array fields serialised via `stringifyList`, parsed back on write). `dry_run=true` by default; output groups by title with `- before` / `+ after` lines per change.

V 0.13.21 - 2026.05.12

* `search-lines` operator now scans array-valued fields (`tags`, `list`) by serialising them through `$tw.utils.stringifyList` first, so the on-disk `.tid` form is what gets matched (multi-word entries wrapped in `[[...]]`).

V 0.13.20 - 2026.05.12

* ''Bugfix'': `reload_tiddlers` now refreshes `$tw.boot.files` for system (`$:/`) tiddlers too. Previously skipped, leaving a window where a `$:/X` file on disk plus an empty `boot.files` entry made TW core's syncer uniquify the filename (`$__X_1.tid`) on the next save.

V 0.13.19 - 2026.05.11

* `reload_mcp_modules` now invalidates `$tw.Wiki.prototype.filterOperators` and `filterRunPrefixes` when those module-types reload, so filter-operator changes (eg `search-lines`) hot-reload without a full server restart.

V 0.13.18 - 2026.05.11

* New `search_lines` MCP tool + `search-lines` filter operator: per-line search with hashline anchors paste-ready for `edit_tiddler`. Regex/words/invert flags, grep-style context via MCP args or `[search-lines[X],[B],[A]]` operator operands (mirrors core `range`).

V 0.13.17 - 2026.05.11

* `extract_html_wiki` uses `storeTiddler` for its `$:/config/FileSystemPaths` write; `addToWikiSilently` moves to `shared.js`.

V 0.13.16 - 2026.05.11

* `upload_file` uses `storeTiddler` to suppress the redundant async write the syncer would otherwise do.

V 0.13.15 - 2026.05.11

* `reload_tiddlers` no longer triggers redundant disk writes for tiddlers it just read from disk; OTP refresh uses the same path. The SyncFilter wrap setup is removed.

V 0.13.14 - 2026.05.11

* ''Bugfix'': `reload_mcp_modules` no longer persists the plugin bundle to disk.

V 0.13.13 - 2026.05.11

* New tool `rename_tiddler` (from, to, overwrite=false, preserve_timestamps=true). Atomic rename: title + on-disk file via FSP. Cross-refs untouched (use `replace_in_tiddlers` later).

* ''Bugfix'': `put_tiddler` / `edit_tiddler` / `rename_tiddler` no longer write a duplicate file when FSP uses tag-based rules.

V 0.13.12 - 2026.05.11

* `reload_tiddlers` output reworked for LLM clarity: rename detection, OTP / scope / change-log labels explicit, disk totals replace `Before/After`, change log no longer lags by one call.

V 0.13.11 - 2026.05.11

* ''Bugfix'': `put_tiddler` / `edit_tiddler` / `resave_tiddler` no longer destroy binary tiddler bodies (SVG, PNG, etc) on save.

V 0.13.10 - 2026.05.10

* `reload_tiddlers` refreshes `$:/config/OriginalTiddlerPaths` when `retain-original-tiddler-path` is set (walks `includeWikis`). Syncer is pointed at `$:/config/wikilabs/tw-mcp/SyncFilter` so OTP is never persisted to disk.

V 0.13.9 - 2026.05.10

* `inspect_tree`: text ≤10 chars verbatim, longer as `…N`; `include:['text']` caps at 2000 chars with head+tail sample.

V 0.13.8 - 2026.05.10

* ''Bugfix'': `inspect_pos` now annotates link and codeblock nodes even when the devtools plugin is not loaded — patches `LinkWidget.renderLink` and `CodeBlockWidget.render` itself for the duration of the render.

V 0.13.7 - 2026.05.10

* `inspect_pos` adds `c="A|B|C"` (caller chain) and `ctx="Title"` (currentTiddler when it differs from the source-context tiddler) on each rendered node.

* MCP `initialize` instructions block tightened to compact LLM form.

V 0.13.6 - 2026.05.10

* ''Bugfix'': `reload_mcp_modules` no longer persists the plugin bundle to the edition's `tiddlers/` folder.

* `inspect_pos` attributes macro-produced DOM nodes back to their defining tiddler in the title-map header and adds `v="<name>"` naming the procedure/macro/variable that produced each node.

* MCP tool descriptions tightened — surface silent-failure traps and hidden constraints in `tools/list`.

V 0.13.4 - 2026.05.09

* SSE inline-threshold default raised from 4 KiB to 32 KiB — doc-sized tiddlers now ride inside the SSE event instead of triggering a syncer fetch (~1 ms vs ~250 ms apply latency).

V 0.13.3 - 2026.05.09

* ''Hardening'': `import_html_wiki` refuses paths with a `.`-prefixed directory or filename segment (`.ssh`, `.aws`, `.env`, …). Other on-disk locations still accepted.

V 0.13.2 - 2026.05.08

* ''Hardening'': MCP write tools (`put_tiddler`, `edit_tiddler`, `resave_tiddler`, `delete_tiddler`, `upload_file`) now reject `title` arguments longer than 1024 chars to prevent OOM via the title index, SSE event payload, and filesystem-path stages.

V 0.13.1 - 2026.05.08

* ''Security'': fix two missed wikitext-injection spots in the //MCP SSE// ControlPanel — the //Current presenter// and //Current main// status lines now render `presenterName` and `mainName` via `<$text>` (same fix v0.12.1 applied to the //Connected clients// sub-panel).

V 0.13.0 - 2026.05.08

* ''Connection-bound `clientId`'' (closes audit H1). Server issues the `clientId` at `/events` connect and returns it via `hello.assignedClientId`; caller-supplied `?clientId=` is ignored. Role routes return `401` unless `X-MCP-Client-Id` is bound to a live connection; `GET /clients` is now admin-only (`403` otherwise).

V 0.12.2 - 2026.05.08

* ''Hardening'': cap concurrent SSE connections at 50; `/presenter/grant` rejects targets that aren't currently connected and caps request body at 1KB.

V 0.12.1 - 2026.05.08

* ''Security'': fix widget injection in the //Connected clients// admin sub-panel — `clientId` and `username` now rendered via `<$text>`. Server validates `clientId` as a strict UUID and caps username at 64 chars.

V 0.12.0 - 2026.05.08

* ''Main mode'': a tab claims the exclusive //i-am-main// admin role. While held, only the admin changes settings or grants presenter; without admin, falls back to last-wins.
* ControlPanel renamed //MCP SSE//. New //Main// section + admin-only //Connected clients// sub-panel with //Grant presenter// buttons. Per-tab UserName via sessionStorage.

V 0.11.0 - 2026.05.08

* ''Presentation mode'': one tab becomes the //presenter//; its per-tab tiddlers (story river, history, state) broadcast to all other tabs (last-claim-wins, released on browser close). ControlPanel //Presenter// section with claim/release buttons.

V 0.10.2 - 2026.05.08

* New ControlPanel //MCP Server// tab with Default/Presentation/Main mode radio (`$:/config/wikilabs/tw-mcp/mode`). UI scaffolding only -- modes activate in v0.11.0+.

V 0.10.1 - 2026.05.08

* SSE: per-tab view-state tiddlers (`$:/StoryList`, `$:/HistoryList`, `$:/state/*`) no longer cross-sync between browser tabs; MCP and filesystem changes still broadcast. Suppression list editable via `$:/config/wikilabs/tw-mcp/per-tab-tiddlers` (TW filter, hot-reloaded).

V 0.10.0 - 2026.05.08

''SSE broadcast sync (server + client).'' New `--mcp sse` keyword adds a `GET /events` Server-Sent Events endpoint for real-time per-tiddler push sync, replacing tiddlyweb's 60-second polling. The browser-side startup module wraps the stock tiddlyweb adaptor at runtime -- no separate plugin install. Echo suppression via `X-MCP-Client-Id`; Last-Event-ID replay via ring buffer. Default `$:/config/SyncPollingInterval` set to 600000 (10-minute fallback). Without `--mcp sse`, polling stays in charge. Full docs in [[MCP SSE Sync]].

V 0.9.4 - 2026.05.04

* `import_html_wiki`: collapse runs of non-alphanumeric characters in tag-derived folder slugs to a single `_` and trim edge separators. Tags like `Higher Caloric Value (H.C.V.)` previously produced `__` runs that the wikitext parser read as underline, breaking list rendering in `Import — Proposed Folder Structure`.

V 0.9.3 - 2026.05.03

* `import_html_wiki` / `extract_html_wiki`: keep 3rd-party (custom) plugins as single `.tid` files (TW unpacks them on boot). Previously they were dropped on restart because the extract filter excluded all plugin tiddlers.
* Skip plugins/themes/languages already loaded by the running `tiddlywiki.info` (tw-mcp, filesystem, …) — they have no `$tw.boot.files` entries and were being duplicated under `_system/plugins/`.
* Trim leading/trailing whitespace and trailing dots from each path component on write. Windows silently strips them, making files like `tiddlers/Gas /Endurance.tid` unreachable without the `\\?\` prefix.

V 0.9.2 - 2026.05.03

* Server version now tracks `plugin.info` (was hardcoded `0.2.0`). Surfaced in the startup log, MCP `initialize` response, `$tw.mcp.version` (+ `heartbeat()`), and the `MCP:` line of `get_wiki_info`.

V 0.9.1 - 2026.05.03

* `import_html_wiki`: drop the wiki-folder path-allowed check on the import source. The source HTML can live anywhere the server can read (Downloads, temp folders, etc.) — matching the v0.7.0 `--mcp file=` behaviour. The populated-folder guard and the `extract_html_wiki` write-side guard still apply.

V 0.9.0 - 2026.05.03

''Breaking:'' `--mcp file=xxx.html` removed. Use the new `import_html_wiki(path)` tool instead, then `extract_html_wiki()` to commit. Refuses on a populated wiki folder or a pending import.

V 0.8.6 - 2026.04.23

* New `reload_mcp_modules` tool: hot-reload MCP server JS modules without restarting the wiki
* Documented hot-reload paths for fresh-session discovery

V 0.8.5 - 2026.04.23

* New `resave_tiddler` tool: rewrite a `.tid` file using current `$:/config/FileSystemPaths`, relocating it if path rules changed; `preserve_timestamps`, `strip_redundant`, `dry_run` options
* Refuses on shadow-only, plugin/theme/language, and `.multids`-bundled tiddlers

V 0.8.4 - 2026.04.20

* `inspect_tree`: always return the JSON tree (was hidden when text had links)
* Cleaner MCP instruction text: better tool-selection hints, fixed broken filter examples

V 0.8.3 - 2026.04.18

* Append workspace tag to label when launched from an IDE

V 0.8.2 - 2026.04.18

* CLI logs: titled takeover block with elapsed time
* Collapse per-client connect/auth/init into one `Client ready` line
* Tag former primary reconnecting as proxy with `[former-primary]`
* Shorten repeated pipe paths to `pipe:…<tail>`
* `mode: READONLY` / `mode: readwrite` replaces `readonly: true/false`

V 0.8.1 - 2026.04.15

* Fix `put_tiddler` silent failure on new tiddlers (0-byte file, false-success response)
* Improve cancellation log to show method + tool name + elapsed time

V 0.8.0 - 2026.04.10

* `inspect_pos`: compact output format — `p="idx:lines"` with title index header
* `inspect_pos`: strip SVG elements and devtools-only attributes (`data-range`, `data-ctx`, `data-caller`)
* Rename: `data-source-pos` → `data-pos` across both plugins
* `get_wiki_info`: fix empty Settings section (use direct settings list instead of `links[]` filter)

V 0.7.0 - 2026.04.07

* Single-file wiki import: `--mcp file=wiki.html` with `extract_html_wiki` tool

V 0.6.1 - 2026.04.07

* Refactor: `textResult()`, `errorResult()`, `persistTiddler()` helpers in shared.js
* Refactor: hashline `HASH_SEP` constant, added space after colon in output
* MCP instructions: persistence warning when `listen` is not active

V 0.6.0 - 2026.04.07

* `inspect_tw`: auto-reduce depth when result exceeds 10K chars
* `run_filter`: show full titles instead of prefix-grouped tree
* `render_tiddler`: add `mode` parameter (raw / viewtemplate)
* `reload_tiddlers`: add `scope` parameter (tiddlers / shadows / all)
* `inspect_tw`: allow `$tw.utils.*` functions in call whitelist
* `inspect_tw`: auto-resolve path + call when path is an object
* New `render_field` tool for rendering individual fields / data indices

V 0.5.0 - 2026.04.02

* initial release
* name: tw-mcp server
